// import { useState, useEffect, useRef } from "react";

// // ════════════════════════════════════════════════════════════════
// //  ARCHITECTURE
// //  Chat shape: { id, title, messages[], createdAt, updatedAt,
// //                jobMode: bool, jobProfile: JobProfile | null }
// //  Message shape (job results): { ...base, jobCards: Job[] | null }
// //    — jobCards attached to AI messages that triggered a job fetch
// //    — rendered as rich cards BELOW the AI bubble
// //  Job flow:
// //    1. Activate Job Mode → auto-fetch → inject cards into first AI msg
// //    2. Intent detected in any message → re-fetch → new AI msg with cards
// //    3. Profile edit → user can re-trigger via "find jobs" any time
// // ════════════════════════════════════════════════════════════════

// const uid = () => Math.random().toString(36).slice(2, 10);
