// import { useState, useEffect, useRef } from "react";

// // ════════════════════════════════════════════════════════════════
// //  ARCHITECTURE
// //  Chat shape: { id, title, messages[], createdAt, updatedAt,
// //                jobMode: bool, jobProfile: JobProfile | null,
// //                docs: DocMeta[] }
// //  DocMeta: { id, name, chunks, size, isPdf, addedAt }
// //
// //  RAW TEXT STORAGE STRATEGY:
// //    • rawText stored in sessionStorage keyed by docId
// //    • sessionStorage: survives page refresh in same tab (~10MB/key)
// //    • localStorage: stores only metadata (no rawText) — stays lean
// //    • On upload:   sessionStorage.setItem(docId, rawText)
// //    • On re-index: sessionStorage.getItem(docId) → always available
// //    • On delete:   sessionStorage.removeItem(docId)
// //    • If sessionStorage missing (new tab): user sees "re-upload needed" badge
// //
// //  RAG PIPELINE:
// //    Upload → extract text → sessionStorage → RAGStore (TF-IDF)
// //    Chat switch → re-index from sessionStorage → RAGStore ready
// //    Query → tokenize → TF-IDF score → top-k chunks → system prompt
// // ════════════════════════════════════════════════════════════════

