// import { useState, useEffect, useRef } from "react";

// // ════════════════════════════════════════════════════════════════
// //  ARCHITECTURE
// //  Chat shape: { id, title, messages[], createdAt, updatedAt,
// //                jobMode: bool, jobProfile: JobProfile | null,
// //                docs: DocMeta[] }
// //  Message shape: { id, role, content, timestamp, ragSource?,
// //                   jobCards?: FormattedJob[] }
// //    jobCards — attached to AI messages triggered by job fetch
// //    rendered as rich cards below the AI bubble
// //
// //  JOB SERVICE LAYER (./services/jobService.js):
// //    getJobsForUser(profile) → POST /match → Job[]
// //    formatJob(job)          → FormattedJob (display-ready)
// //
// //  JOB FLOW:
// //    activateJob(profile) → save chat → fetchAndShowJobs()
// //    isJobIntent(text)    → fetchAndShowJobs()  [on any matching msg]
// //    fetchAndShowJobs()   → getJobsForUser → formatJob → callAI (intro)
// //                        → save aiMsg { content, jobCards }
// //
// //  RAW TEXT STORAGE:
// //    sessionStorage keyed by docId — survives refresh, ~10MB/key
// // ════════════════════════════════════════════════════════════════

