// 12
import { useState, useEffect, useRef, useCallback } from "react";
import { Tldraw } from 'tldraw'
import 'tldraw/tldraw.css'

// ════════════════════════════════════════════════════════════════
//  ARCHITECTURE
//  Chat shape: { id, title, messages[], createdAt, updatedAt,
//                jobMode: bool, jobProfile: JobProfile | null,
//                docs: DocMeta[] }
//  Message shape: { id, role, content, timestamp, ragSource?,
//                   jobCards?: FormattedJob[] }
//    jobCards — attached to AI messages triggered by job fetch
//    rendered as rich cards below the AI bubble
//
//  AI LAYER:
//    callAI(messages, system) → POST localhost:5000/api/chat
//    server.js → Groq API (llama-3.3-70b-versatile)
//    API key lives on server only — never in the browser
//
//  JOB SERVICE LAYER:
//    getJobsForUser(profile) → POST localhost:3001/match → Job[]
//    formatJob(job)          → FormattedJob (display-ready)
//
//  JOB FLOW:
//    activateJob(profile) → save chat → fetchAndShowJobs()
//    isJobIntent(text)    → fetchAndShowJobs()  [on any matching msg]
//    fetchAndShowJobs()   → getJobsForUser → formatJob → callAI (intro)
//                        → save aiMsg { content, jobCards }
//
//  RAW TEXT STORAGE:
//    sessionStorage keyed by docId — survives refresh, ~10MB/key
//
//  WHITEBOARD:
//    boardOpen state → tldraw panel renders beside .main
//    snapshot saved to localStorage key "nx_board_snapshot"
//    resizable via drag handle — boardWidth state (default 520px)
// ════════════════════════════════════════════════════════════════

const uid = () => Math.random().toString(36).slice(2, 10);
const now = () => new Date().toISOString();
const fmtTime = iso => new Date(iso).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
const fmtDate = iso => {
  const d = new Date(iso), t = new Date();
  if (d.toDateString() === t.toDateString()) return "Today";
  const y = new Date(t); y.setDate(t.getDate() - 1);
  if (d.toDateString() === y.toDateString()) return "Yesterday";
  return d.toLocaleDateString([], { month: "short", day: "numeric" });
};

const S = {
  get: k => { try { return JSON.parse(localStorage.getItem(k)); } catch { return null; } },
  set: (k, v) => localStorage.setItem(k, JSON.stringify(v)),
  del: k => localStorage.removeItem(k),
};

// ─── RAG text storage: sessionStorage (survives refresh, ~10MB/key) ──────────
// Much better than in-memory Map (lost on refresh) or localStorage (5MB total)
const RTS = {
  set: (id, rawText) => {
    try { sessionStorage.setItem(`rag_${id}`, rawText); return true; }
    catch(e) { console.warn("sessionStorage full, falling back:", e); return false; }
  },
  get: (id) => { try { return sessionStorage.getItem(`rag_${id}`) || null; } catch { return null; } },
  del: (id) => { try { sessionStorage.removeItem(`rag_${id}`); } catch {} },
  has: (id) => { try { return sessionStorage.getItem(`rag_${id}`) !== null; } catch { return false; } },
};

// ─── Job Service (inlined from ./services/jobService.js) ─────────────────────
// Uses Vite env var with fallback to localhost for dev
// Vite exposes env vars via import.meta.env
// Add to client/.env: VITE_JOB_SERVICE_URL=http://localhost:3001
const JOB_SERVICE_URL = import.meta.env.VITE_JOB_SERVICE_URL || "http://localhost:3001";

async function getJobsForUser(profile) {
  const res = await fetch(JOB_SERVICE_URL + "/match", {
    method:  "POST",
    headers: { "Content-Type": "application/json" },
    body:    JSON.stringify(profile),
  });
  if (!res.ok) throw new Error("Job service error: " + res.status);
  const { jobs } = await res.json();
  return jobs; // sorted by matchScore descending
}

function formatJob(job) {
  const salary =
    job.salary_min && job.salary_max
      ? "₹" + (job.salary_min/1e5).toFixed(1) + "–" + (job.salary_max/1e5).toFixed(1) + " LPA"
      : job.salary_min
      ? "₹" + (job.salary_min/1e5).toFixed(1) + "+ LPA"
      : "Not disclosed";

  const exp =
    job.experience_min != null && job.experience_max != null
      ? job.experience_min === job.experience_max
        ? job.experience_min + " yr"
        : job.experience_min + "–" + job.experience_max + " yrs"
      : job.experience_min != null
      ? job.experience_min + "+ yrs"
      : "Any exp";

  const locType = { remote:"🌐 Remote", hybrid:"🏠 Hybrid", onsite:"🏢 Onsite" }[job.location_type] || "";

  return {
    id:         job.id || uid(),
    title:      job.title       || "Untitled Role",
    company:    job.company     || "Unknown Company",
    location:   [job.location, locType].filter(Boolean).join(" · "),
    salary,
    experience: exp,
    jobType:    job.job_type    || "",
    skills:     (job.skills     || []).slice(0, 6),
    portal:     job.source_portal || "",
    applyUrl:   job.source_url  || "",
    matchScore: job.matchScore  || 0,
    matchWhy:   (job.matchReasons || []).join(", "),
  };
}

// ─── Intent detection — natural language triggers for job fetch ───────────────
const JOB_INTENT_RE = [
  /find\s*(me\s*)?(jobs?|roles?|openings?|positions?|work|opportunities)/i,
  /show\s*(me\s*)?(jobs?|roles?|openings?|listings?|matches?)/i,
  /get\s*(me\s*)?(jobs?|roles?|openings?|positions?)/i,
  /search\s*(for\s*)?(jobs?|roles?|openings?)/i,
  /what\s*(jobs?|roles?|positions?|openings?)\s*(match|suit|fit|are)/i,
  /any\s*(new\s*)?(jobs?|roles?|openings?)/i,
  /latest\s*(jobs?|openings?|matches?)/i,
  /job\s*(matches?|results?|listings?|recommendations?)/i,
  /fetch\s*(jobs?|listings?|openings?)/i,
  /refresh\s*(jobs?|matches?|listings?)/i,
  /matching\s*(jobs?|roles?|positions?)/i,
  /new\s*(openings?|positions?|roles?)/i,
];

function isJobIntent(text) {
  return JOB_INTENT_RE.some(re => re.test(text));
}

async function callAI(messages, system) {
  const res = await fetch("http://localhost:5000/api/chat", {
    method:  "POST",
    headers: { "Content-Type": "application/json" },
    body:    JSON.stringify({ messages, system }),
  });
  if (!res.ok) {
    const e = await res.json().catch(() => ({}));
    throw new Error(e?.error || `Server error ${res.status}`);
  }
  const d = await res.json();
  return d.reply || "";
}





// ══════════════════════════════════════════════════════════════════════════════
//  PHASE 1 RAG ARCHITECTURE
//  Ingestion  → Section Parser → Structured Chunks { section, entity, content }
//  Query      → Intent Classifier → Metadata Filter → Context Builder
//  Generation → Strict prompt with only relevant chunks
// ══════════════════════════════════════════════════════════════════════════════

// ─── Step 1: Normalize raw text ───────────────────────────────────────────────
function normalizeText(text) {
  return text
    .replace(/\r\n/g, "\n")
    .replace(/\n{4,}/g, "\n\n\n")
    .replace(/[ \t]{2,}/g, " ")
    .replace(/-[ \t]*\n[ \t]*/g, "")           // fix PDF hyphenation
    .replace(/\n--- Page \d+ ---/g, "\n\n")    // strip pdf.js page markers
    .trim();
}

// ─── Step 2: Section Parser ───────────────────────────────────────────────────
// Detects resume section headers and tags each paragraph with its section.
// Returns: Array of { sectionType, rawHeader, paragraphs[] }
const SECTION_PATTERNS = [
  { type: "contact",      pattern: /^(contact|personal\s+info|profile|about\s+me)/i },
  { type: "skills",       pattern: /^(technical\s+skills?|skills?|achievements?|competenc)/i },
  { type: "experience",   pattern: /^(work\s+experience|experience|employment|internship|professional\s+experience)/i },
  { type: "projects",     pattern: /^(projects?|personal\s+projects?|technical\s+projects?|key\s+projects?)/i },
  { type: "education",    pattern: /^(education|academic|qualification|degree)/i },
  { type: "certifications", pattern: /^(certification|certif|license|course)/i },
  { type: "awards",       pattern: /^(awards?|honors?|achievements?|recognition)/i },
  { type: "publications", pattern: /^(publications?|research|papers?)/i },
  { type: "languages",    pattern: /^(languages?|spoken\s+languages?)/i },
];

function detectSectionType(line) {
  const clean = line.trim();
  for (const { type, pattern } of SECTION_PATTERNS) {
    if (pattern.test(clean)) return type;
  }
  return null;
}

// A line is likely a section header if it:
// - Is short (< 60 chars), AND
// - Is title-cased or all-caps, AND
// - Not a bullet point or sentence
function isSectionHeader(line) {
  const t = line.trim();
  if (!t || t.length > 60 || t.startsWith("-") || t.startsWith("•") || t.startsWith("*")) return false;
  if (/[.!?]$/.test(t) && t.length > 30) return false; // long sentence ending in punctuation
  const isTitleCase = t[0] === t[0].toUpperCase() && /[A-Z]/.test(t[0]);
  const isAllCaps = t === t.toUpperCase() && /[A-Z]/.test(t);
  const hasNoLowerStart = !/^[a-z]/.test(t);
  return (isTitleCase || isAllCaps) && hasNoLowerStart && detectSectionType(t) !== null;
}

function parseSections(rawText) {
  const normalized = normalizeText(rawText);
  const lines = normalized.split("\n");
  const sections = [];
  let currentSection = { type: "header", header: "", paragraphs: [], rawLines: [] };

  for (const line of lines) {
    const trimmed = line.trim();
    if (isSectionHeader(trimmed)) {
      // Save previous section if it has content
      if (currentSection.rawLines.length > 0) {
        currentSection.paragraphs = buildParagraphs(currentSection.rawLines);
        sections.push(currentSection);
      }
      currentSection = {
        type: detectSectionType(trimmed) || "general",
        header: trimmed,
        rawLines: [],
        paragraphs: [],
      };
    } else {
      currentSection.rawLines.push(line);
    }
  }
  // Flush last section
  if (currentSection.rawLines.length > 0) {
    currentSection.paragraphs = buildParagraphs(currentSection.rawLines);
    sections.push(currentSection);
  }

  return sections;
}

function buildParagraphs(lines) {
  const paras = [];
  let buf = [];
  for (const line of lines) {
    if (line.trim() === "") {
      if (buf.length > 0) { paras.push(buf.join("\n").trim()); buf = []; }
    } else {
      buf.push(line);
    }
  }
  if (buf.length > 0) paras.push(buf.join("\n").trim());
  return paras.filter(p => p.length > 10);
}

// ─── Step 3: Entity Extractor ─────────────────────────────────────────────────
// Extracts individual entities (companies/projects) from structured sections.
// Each entity = { name, titleBlock, role, content[], dates }
// Key fix: entity is saved even if content is in NEXT paragraphs —
// we never drop an entity just because content arrives after the title.

const DATE_PATTERN = /(?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t(?:ember)?)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)?\s*\d{4}\s*[-–—to]+\s*(?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t(?:ember)?)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)?\s*(?:\d{4}|present|current)/gi;

function extractEntities(section) {
  if (!["experience","projects","education","certifications"].includes(section.type)) {
    return null;
  }

  const paragraphs = section.paragraphs;
  if (paragraphs.length === 0) return null;

  const entities = [];
  let currentEntity = null;

  function isEntityHeader(para) {
    // Entity header = short paragraph that has a date OR looks like "Company Name\nRole Title"
    DATE_PATTERN.lastIndex = 0;
    const hasDate = DATE_PATTERN.test(para);
    DATE_PATTERN.lastIndex = 0;
    const lines = para.split("\n").map(l => l.trim()).filter(Boolean);
    const isShort = para.length < 200;
    const noBullets = !/^[-•*●]/.test(para.trim()) && !para.includes("\n-") && !para.includes("\n•") && !para.includes("\n●");
    const startsCapital = lines.length > 0 && /^[A-Z]/.test(lines[0]);
    return isShort && noBullets && startsCapital && (hasDate || lines.length <= 3);
  }

  function flushEntity() {
    if (!currentEntity) return;
    // Always save — even if content is empty (title-only entry)
    entities.push(currentEntity);
    currentEntity = null;
  }

  for (const para of paragraphs) {
    if (isEntityHeader(para)) {
      flushEntity();

      // Extract company name and role from the title block
      // Format can be: "Company Name    Aug 2025 - Sept 2025\nRole Title"
      // or: "Company Name\nRole Title\nAug 2025 - Sept 2025"
      const lines = para.split("\n").map(l => l.trim()).filter(Boolean);
      DATE_PATTERN.lastIndex = 0;
      const dates = (para.match(DATE_PATTERN) || []).join(", ");
      DATE_PATTERN.lastIndex = 0;

      // Company name = first line, stripped of date
      const companyName = lines[0].replace(DATE_PATTERN, "").replace(/\s{2,}/g," ").trim();
      DATE_PATTERN.lastIndex = 0;

      // Role = second line if it exists and doesn't look like a date
      const roleLine = lines.length > 1 ? lines[1].replace(DATE_PATTERN,"").trim() : "";
      DATE_PATTERN.lastIndex = 0;

      currentEntity = {
        name: companyName || para.slice(0, 60),
        role: roleLine,
        titleBlock: para,
        content: [],
        dates,
      };
    } else if (currentEntity) {
      // Content paragraph — attach to current entity
      currentEntity.content.push(para);
    } else {
      // No entity started yet — create generic container
      currentEntity = {
        name: section.header,
        role: "",
        titleBlock: "",
        content: [para],
        dates: "",
      };
    }
  }
  flushEntity(); // flush last entity

  return entities.length > 0 ? entities : null;
}

// ─── Step 4: Build Structured Chunks ─────────────────────────────────────────
// Each chunk = { text, metadata: { section, entity, entityType, docName } }
function buildStructuredChunks(rawText, docName) {
  const sections = parseSections(rawText);
  const chunks = [];

  for (const section of sections) {
    const entities = extractEntities(section);

    if (entities) {
      // Entity-aware chunking: one chunk per entity
      for (const entity of entities) {
        // Build rich text: title + role + all content bullets together
        // This keeps "Elevate Labs | Software Engineer Intern" + bullets in ONE chunk
        const parts = [];
        if (entity.name) parts.push(entity.name + (entity.dates ? " | " + entity.dates : ""));
        if (entity.role) parts.push(entity.role);
        if (entity.titleBlock && entity.titleBlock !== entity.name) {
          // Include full title block only if it adds info beyond name+role
          const tb = entity.titleBlock.replace(entity.name,"").replace(entity.role||"","").trim();
          if (tb.length > 5) parts.push(tb);
        }
        parts.push(...entity.content);

        const contentText = parts.filter(Boolean).join("\n\n").trim();
        if (contentText.length < 15) continue;

        chunks.push({
          text: contentText,
          metadata: {
            section:    section.type,
            entity:     entity.name,
            role:       entity.role,
            entityType: section.type,
            dates:      entity.dates,
            docName,
          },
        });
      }
    } else {
      // Flat section chunking: one chunk for the whole section
      const fullText = section.paragraphs.join("\n\n").trim();
      if (fullText.length < 15) continue;

      // If flat section is very large, split by your Python chunker logic
      if (fullText.length > 1200) {
        const subChunks = smartChunk(fullText, 1000, 200);
        subChunks.forEach((sc, i) => {
          chunks.push({
            text: sc,
            metadata: {
              section:    section.type,
              entity:     section.header,
              entityType: "flat",
              docName,
              subIndex:   i,
            },
          });
        });
      } else {
        chunks.push({
          text: fullText,
          metadata: {
            section:    section.type,
            entity:     section.header,
            entityType: "flat",
            docName,
          },
        });
      }
    }
  }

  // Fallback: if parser produced nothing, return whole text as one chunk
  if (chunks.length === 0) {
    chunks.push({
      text: normalizeText(rawText),
      metadata: { section: "general", entity: docName, entityType: "flat", docName },
    });
  }

  return chunks;
}

// ─── Python-style flat chunker (used for oversized flat sections) ─────────────
function smartChunk(text, chunkSize, overlap) {
  chunkSize = chunkSize || 1000;
  overlap   = overlap   || 200;

  const sections = text.split(/\n[ \t]*\n+/).map(s => s.trim()).filter(Boolean);
  const chunks = [];
  let currentChunk = [];
  let currentLen = 0;

  function flush() {
    const joined = currentChunk.join(" ").trim();
    if (joined.length > 50) chunks.push(joined);
    const ov = joined.length > overlap ? joined.slice(-overlap) : joined;
    currentChunk = ov ? [ov] : [];
    currentLen = ov ? ov.length : 0;
  }

  for (const section of sections) {
    if (section.length > chunkSize) {
      if (currentChunk.length > 0) flush();
      const sentences = section.split(/(?<=[.!?])\s+/).map(s => s.trim()).filter(Boolean);
      for (const sent of sentences) {
        if (currentLen + sent.length > chunkSize && currentChunk.length > 0) flush();
        currentChunk.push(sent);
        currentLen += sent.length;
      }
    } else {
      if (currentLen + section.length > chunkSize && currentChunk.length > 0) flush();
      currentChunk.push(section);
      currentLen += section.length;
    }
  }
  if (currentChunk.length > 0) {
    const last = currentChunk.join(" ").trim();
    if (last.length > 50) chunks.push(last);
  }
  if (chunks.length === 0 && text.trim()) chunks.push(text.trim());
  return chunks;
}

// ─── Step 5: Intent Classifier ────────────────────────────────────────────────
// Classifies query into structured intent WITHOUT an LLM call
// Returns: { type, section, entityHint, isGeneral }
const SECTION_KEYWORDS = {
  experience:   ["experience","work","job","role","intern","internship","company","companies","employer","employment","position","did","doing","worked","responsibilities","tasks","achieve","contributed"],
  projects:     ["project","projects","built","build","created","developed","app","application","system","tool","website","chatbot","platform"],
  skills:       ["skill","skills","technology","technologies","tech","stack","know","language","framework","tool","database","cloud","proficient","expertise"],
  education:    ["education","study","studied","college","university","degree","cgpa","grade","gpa","graduation","school","course"],
  certifications:["certification","certified","certificate","license","course","completed"],
  contact:      ["contact","email","phone","number","linkedin","github","location","address"],
};

// Known entity extractors — pull company/project names from query
function extractEntityHint(query) {
  // We'll match against stored chunk metadata at query time
  // Here just return the raw query for matching
  return query;
}

function classifyIntent(query) {
  const q = query.toLowerCase();
  const scores = {};

  for (const [section, keywords] of Object.entries(SECTION_KEYWORDS)) {
    scores[section] = keywords.filter(k => q.includes(k)).length;
  }

  const topSection = Object.entries(scores).sort((a,b)=>b[1]-a[1])[0];
  const isGeneral = topSection[1] === 0;

  return {
    type:        isGeneral ? "general" : "section_specific",
    section:     isGeneral ? null : topSection[0],
    entityHint:  extractEntityHint(query),
    isGeneral,
    scores,
  };
}

// ─── Step 6: Structured RAGStore ─────────────────────────────────────────────
class RAGStore {
  constructor() { this.docs = []; }

  _tokenize(text) {
    const STOPS = new Set(["the","and","for","are","but","not","you","all","any","can","was","one","our","out","use","had","how","its","has","have","this","that","with","they","will","from","been","were","said","each","which","their","there","what","about","into","than","them","then","some","time","could","would","should","when","your","just","like","more","also","other","over","such","very","these","those","using","used","per","make","made","well","need","able","many","both","high","good"]);
    return text.toLowerCase().replace(/[^a-z0-9\s]/g," ").split(/\s+/).filter(w=>w.length>1&&!STOPS.has(w));
  }

  // Add doc: parse into structured chunks with metadata
  add(id, name, rawText) {
    this.docs = this.docs.filter(d => d.id !== id);
    const structuredChunks = buildStructuredChunks(rawText, name);
    // Tokenize each chunk for TF-IDF fallback
    const chunks = structuredChunks.map(c => ({
      text:     c.text,
      metadata: c.metadata,
      tokens:   this._tokenize(c.text),
    }));
    this.docs.push({ id, name, rawText, chunks });
    console.log("[RAG] Structured chunks for", name + ":");
    chunks.forEach((c,i) => console.log(`  [${i}] section=${c.metadata.section} entity="${c.metadata.entity}" len=${c.text.length}`));
    return chunks.length;
  }

  remove(id) { this.docs = this.docs.filter(d => d.id !== id); }

  clear() { this.docs = []; }

  // Smart query: classify intent → filter → rank
  query(queryText, k) {
    k = k || 6;
    if (!this.docs.length) return [];

    // Small doc threshold — inject full text for very small docs (< 3000 chars)
    // This handles name/contact/one-liner answers
    const totalRaw = this.docs.reduce((s,d)=>s+(d.rawText||"").length,0);
    if (totalRaw < 3000) {
      return this.docs.map(d=>({
        text: d.rawText, name: d.name, metadata:{ section:"full", entity:d.name },
        score:1, isFullDoc:true,
      }));
    }

    // ── Classify intent ────────────────────────────────────────────────────────
    const intent = classifyIntent(queryText);
    const qLower = queryText.toLowerCase();

    // ── Gather all chunks from all docs ───────────────────────────────────────
    let allChunks = this.docs.flatMap(d =>
      d.chunks.map(c => ({ ...c, docName: d.name }))
    );

    // ── Metadata filter (the key fix) ─────────────────────────────────────────
    let filtered = allChunks;

    if (!intent.isGeneral && intent.section) {
      // Filter by detected section
      const sectionFiltered = allChunks.filter(c =>
        c.metadata.section === intent.section
      );
      if (sectionFiltered.length > 0) filtered = sectionFiltered;
    }

    // ── Entity filter: check if query mentions a specific entity name ──────────
    // Uses multi-word prefix matching to avoid false positives
    const entityNames = [...new Set(allChunks.map(c=>c.metadata.entity.toLowerCase()))];
    const mentionedEntity = entityNames.find(e => {
      if (e.length <= 3) return false;
      // Match full entity name OR first two words (e.g. "elevate labs" from "Elevate Labs Inc")
      const words = e.split(/\s+/).filter(Boolean);
      const twoWordPrefix = words.slice(0, 2).join(" ");
      return qLower.includes(e) || (twoWordPrefix.length > 5 && qLower.includes(twoWordPrefix));
    });

    if (mentionedEntity) {
      const entityFiltered = filtered.filter(c => {
        const entityLower = c.metadata.entity.toLowerCase();
        const words = mentionedEntity.split(/\s+/).filter(Boolean);
        const twoWordPrefix = words.slice(0, 2).join(" ");
        return entityLower.includes(twoWordPrefix) || entityLower.includes(mentionedEntity);
      });
      if (entityFiltered.length > 0) {
        filtered = entityFiltered;
        console.log("[RAG] Entity filter matched:", mentionedEntity, "→", filtered.length, "chunks");
      }
    }

    console.log("[RAG] Intent:", JSON.stringify(intent));
    console.log("[RAG] After filter:", filtered.length, "of", allChunks.length, "chunks");

    // ── TF-IDF ranking on filtered set ────────────────────────────────────────
    const qTokens = this._tokenize(queryText);
    if (qTokens.length === 0) return filtered.slice(0, k).map(c=>({...c,score:0}));

    // Compute IDF over filtered set
    const N = filtered.length || 1;
    const idf = term => {
      const df = filtered.filter(c=>c.tokens.includes(term)).length;
      return Math.log((N+1)/(df+1))+1;
    };
    const tf = tokens => {
      const f={};
      tokens.forEach(t=>f[t]=(f[t]||0)+1);
      const total=tokens.length||1;
      Object.keys(f).forEach(k=>f[k]/=total);
      return f;
    };

    const ranked = filtered.map(c => {
      const tfMap = tf(c.tokens);
      const score = qTokens.reduce((s,t)=>s+(tfMap[t]||0)*idf(t),0);
      return { ...c, score };
    }).sort((a,b)=>b.score-a.score);

    // Return top-k but ensure we don't drop important low-scoring chunks
    // If entity was mentioned and filter gave ≤3 chunks, return all of them
    if (mentionedEntity && filtered.length <= 3) {
      return filtered.map(c=>({...c,score:1}));
    }

    return ranked.slice(0, k);
  }

  get size() { return this.docs.reduce((s,d)=>s+d.chunks.length,0); }
  get docCount() { return this.docs.length; }
}

function buildJobSystem(profile) {
  if (!profile) return "";
  const p = profile;
  const links = Object.entries(p.codingProfiles || {}).filter(([,v]) => v).map(([k,v]) => `${k}: ${v}`).join(", ");
  const projs = (p.projects || []).filter(x => x.name).map(x => `• ${x.name}: ${x.desc}${x.link ? ` (${x.link})` : ""}`).join("\n");
  return `You are Nexus in Job Search Mode — a dedicated AI career assistant with deep knowledge of the tech job market, Indian and global hiring, compensation, and interview processes.

CANDIDATE PROFILE:
Name: ${p.name||"—"} | Location: ${p.location||"—"} | Target Role: ${p.targetRole||"—"}
Experience: ${p.experience||"—"} | Notice Period: ${p.noticePeriod||"—"}
Current CTC: ${p.currentCTC||"—"} | Expected CTC: ${p.expectedCTC||"—"}
Job Type: ${p.jobType||"—"} | Preferred Locations: ${p.preferredLocations||"—"}

EDUCATION: ${p.college||"—"} | ${p.degree||"—"} | Grad: ${p.graduationYear||"—"} | CGPA: ${p.cgpa||"—"}

TECH STACK:
Languages: ${p.techStack||"—"} | Frameworks: ${p.frameworks||"—"}
Databases: ${p.databases||"—"} | Cloud/DevOps: ${p.cloud||"—"}

CODING PROFILES: ${links||"—"}
PROJECTS:\n${projs||"—"}
ACHIEVEMENTS: ${p.achievements||"—"}
${p.resumeText ? `\nRESUME CONTENT:\n${p.resumeText.slice(0,1500)}` : ""}

INSTRUCTIONS:
- Always keep this candidate's full profile in mind
- Give tailored, specific advice for their exact stack and experience
- Help with: job search strategy, resume review, interview prep, salary negotiation, company research
- Suggest specific companies, roles, and job portals (LinkedIn, Naukri, Unstop, Wellfound, etc.)
- Be proactive and give concrete actionable steps

FORMAT RULES:
- Use ## headings for major sections (e.g., ## Resume Tips, ## Target Companies)
- Use **bold** for company names, role titles, important keywords
- Use numbered lists for steps/rankings, bullet lists for options
- Use tables to compare companies, salaries, or options side by side
- Use \`code\` for technical terms, CLI commands, tech names
- Keep answers well-structured and scannable`;
}

function Markdown({ text }) {
  if (!text) return null;

  const inlineFormat = (str, keyPfx) => {
    const parts = [];
    const re = /(\*\*(.+?)\*\*|\*(.+?)\*|`([^`]+)`|\[([^\]]+)\]\(([^)]+)\))/g;
    let last = 0, m, ki = 0;
    while ((m = re.exec(str)) !== null) {
      if (m.index > last) parts.push(str.slice(last, m.index));
      if (m[0].startsWith("**"))       parts.push(<strong key={keyPfx+ki++}>{m[2]}</strong>);
      else if (m[0].startsWith("*"))   parts.push(<em key={keyPfx+ki++}>{m[3]}</em>);
      else if (m[0].startsWith("`"))   parts.push(<code key={keyPfx+ki++}>{m[4]}</code>);
      else if (m[0].startsWith("["))   parts.push(<a key={keyPfx+ki++} href={m[6]} target="_blank" rel="noreferrer">{m[5]}</a>);
      last = m.index + m[0].length;
    }
    if (last < str.length) parts.push(str.slice(last));
    return parts.length ? parts : str;
  };

  const lines = text.split("\n");
  const out = [];
  let i = 0;

  while (i < lines.length) {
    const l = lines[i];

    if (l.startsWith("```")) {
      const lang = l.slice(3).trim();
      const codeBuf = [];
      i++;
      while (i < lines.length && !lines[i].startsWith("```")) { codeBuf.push(lines[i]); i++; }
      out.push(
        <div key={`cb${i}`} className="md-code-wrap">
          {lang && <div className="md-code-lang">{lang}</div>}
          <pre><code>{codeBuf.join("\n")}</code></pre>
        </div>
      );
      i++; continue;
    }

    if (/^(-{3,}|_{3,}|\*{3,})$/.test(l.trim())) {
      out.push(<hr key={`hr${i}`} className="md-hr"/>); i++; continue;
    }

    const h = l.match(/^(#{1,3})\s+(.+)/);
    if (h) {
      const lvl = h[1].length;
      const Tag = `h${lvl}`;
      out.push(<Tag key={`h${i}`} className={`md-h${lvl}`}>{inlineFormat(h[2], `h${i}`)}</Tag>);
      i++; continue;
    }

    if (l.startsWith("> ")) {
      const bqLines = [];
      while (i < lines.length && lines[i].startsWith("> ")) { bqLines.push(lines[i].slice(2)); i++; }
      out.push(<blockquote key={`bq${i}`} className="md-bq">{bqLines.map((bl,bi)=><p key={bi}>{inlineFormat(bl,`bq${i}${bi}`)}</p>)}</blockquote>);
      continue;
    }

    if (/^[-*+]\s/.test(l)) {
      const items = [];
      while (i < lines.length && /^[-*+]\s/.test(lines[i])) {
        items.push(<li key={i}>{inlineFormat(lines[i].replace(/^[-*+]\s/,""), `ul${i}`)}</li>);
        i++;
      }
      out.push(<ul key={`ul${i}`} className="md-ul">{items}</ul>);
      continue;
    }

    if (/^\d+\.\s/.test(l)) {
      const items = [];
      while (i < lines.length && /^\d+\.\s/.test(lines[i])) {
        items.push(<li key={i}>{inlineFormat(lines[i].replace(/^\d+\.\s/,""), `ol${i}`)}</li>);
        i++;
      }
      out.push(<ol key={`ol${i}`} className="md-ol">{items}</ol>);
      continue;
    }

    if (l.includes("|") && l.trim().startsWith("|")) {
      const rows = [];
      while (i < lines.length && lines[i].includes("|") && lines[i].trim().startsWith("|")) {
        rows.push(lines[i]); i++;
      }
      const isHeader = rows[1] && /^[|\s:-]+$/.test(rows[1]);
      const dataRows = isHeader ? [rows[0], ...rows.slice(2)] : rows;
      const parsed = dataRows.map(r => r.replace(/^\||\|$/g,"").split("|").map(c=>c.trim()));
      out.push(
        <div key={`tbl${i}`} className="md-table-wrap">
          <table className="md-table">
            {isHeader && <thead><tr>{parsed[0].map((c,ci)=><th key={ci}>{inlineFormat(c,`th${i}${ci}`)}</th>)}</tr></thead>}
            <tbody>{(isHeader?parsed.slice(1):parsed).map((row,ri)=><tr key={ri}>{row.map((c,ci)=><td key={ci}>{inlineFormat(c,`td${i}${ri}${ci}`)}</td>)}</tr>)}</tbody>
          </table>
        </div>
      );
      continue;
    }

    if (l.trim() === "") { i++; continue; }

    out.push(<p key={`p${i}`} className="md-p">{inlineFormat(l, `p${i}`)}</p>);
    i++;
  }

  return <div className="md">{out}</div>;
}

// ═══════════════════ STYLES ═══════════════════════════════════════
const CSS = `
@import url('https://fonts.googleapis.com/css2?family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600&family=DM+Mono:wght@400;500&display=swap');
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --bg:#0c0c0f;--bg2:#131318;--bg3:#1a1a22;--bg4:#22222d;--bg5:#2b2b38;
  --br:#252530;--br2:#32323f;
  --tx:#e8e8ef;--tx2:#8888a0;--tx3:#50506a;
  --ac:#7c6af7;--ac2:#a599fb;--ac-bg:rgba(124,106,247,.10);
  --gn:#34d399;--gn-bg:rgba(52,211,153,.09);
  --rd:#f87171;--rd-bg:rgba(248,113,113,.09);
  --am:#fbbf24;--am-bg:rgba(251,191,36,.09);
  --bl:#60a5fa;--bl-bg:rgba(96,165,250,.09);
  --r:10px;--rl:14px;--rxl:20px;
  --font:'DM Sans',sans-serif;--mono:'DM Mono',monospace;
  --sh:0 1px 12px rgba(0,0,0,.4);--shl:0 8px 40px rgba(0,0,0,.6);
  --sw:256px;--tr:.16s ease;
}
[data-theme=light]{
  --bg:#f2f2f5;--bg2:#ffffff;--bg3:#eaeaef;--bg4:#dcdce6;--bg5:#ceceda;
  --br:#e0e0ea;--br2:#d0d0de;
  --tx:#16161e;--tx2:#52527a;--tx3:#9090b0;
  --ac:#5b4ce0;--ac2:#7c6af7;--ac-bg:rgba(91,76,224,.09);
  --gn:#059669;--gn-bg:rgba(5,150,105,.08);
  --rd:#dc2626;--rd-bg:rgba(220,38,38,.08);
  --am:#d97706;--am-bg:rgba(217,119,6,.08);
  --bl:#2563eb;--bl-bg:rgba(37,99,235,.08);
  --sh:0 1px 8px rgba(0,0,0,.07);--shl:0 8px 28px rgba(0,0,0,.11);
}
html,body,#root{height:100%;width:auto;overflow:hidden;font-family:var(--font);background:var(--bg);color:var(--tx)}
button{cursor:pointer;border:none;background:none;font-family:var(--font);color:inherit}
input,textarea,select{font-family:var(--font);color:var(--tx)}
::-webkit-scrollbar{width:4px;height:4px}::-webkit-scrollbar-track{background:transparent}
::-webkit-scrollbar-thumb{background:var(--br2);border-radius:4px}

.app{display:flex;height:100dvh;overflow:hidden;position:relative}
.main{flex:1;display:flex;flex-direction:column;overflow:hidden;min-width:0}

.sidebar{width:var(--sw);min-width:var(--sw);height:100dvh;background:var(--bg2);border-right:1px solid var(--br);display:flex;flex-direction:column;transition:transform var(--tr);flex-shrink:0;z-index:20}
.sidebar-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:19;backdrop-filter:blur(2px)}
.app.collapsed .sidebar{transform:translateX(-100%);position:absolute;height:100%}
@media(max-width:768px){
  .sidebar{position:fixed;top:0;left:0;height:100dvh;transform:translateX(-100%)}
  .sidebar.open{transform:translateX(0);box-shadow:var(--shl)}
  .sidebar-overlay.visible{display:block}
  .app.collapsed .sidebar{transform:translateX(-100%);position:fixed}
}

.s-head{height:52px;padding:14px 12px;display:flex;align-items:center;gap:7px;border-bottom:1px solid var(--br);flex-shrink:0}
.logo{display:flex;align-items:center;gap:8px;flex:1;min-width:0}
.logo-dot{width:26px;height:26px;background:var(--ac);border-radius:8px;display:grid;place-items:center;flex-shrink:0}
.logo-dot svg{width:14px;height:14px;fill:white}
.logo-name{font-size:14.5px;font-weight:600;letter-spacing:-.3px;color:var(--tx)}
.ib{width:32px;height:32px;border-radius:8px;display:grid;place-items:center;color:var(--tx3);transition:all var(--tr);flex-shrink:0;-webkit-tap-highlight-color:transparent}
.ib:hover{background:var(--bg3);color:var(--tx2)}
.ib svg{width:16px;height:16px;stroke:currentColor;stroke-width:1.8;fill:none}

.s-new{display:flex;align-items:center;gap:8px;margin:8px 8px 4px;padding:9px 12px;border-radius:var(--r);font-size:13px;font-weight:500;color:var(--tx2);transition:all var(--tr);width:calc(100% - 16px);border:1px solid transparent;-webkit-tap-highlight-color:transparent}
.s-new:hover{background:var(--bg3);color:var(--tx);border-color:var(--br)}
.s-new svg{width:14px;height:14px;stroke:var(--ac);stroke-width:2;fill:none;flex-shrink:0}

.s-hist{flex:1;overflow-y:auto;padding:2px 6px 8px;-webkit-overflow-scrolling:touch}
.s-gl{font-size:10px;font-weight:700;letter-spacing:.07em;text-transform:uppercase;color:var(--tx3);padding:10px 8px 3px;user-select:none}
.s-item{display:flex;align-items:center;gap:6px;padding:8px 10px;border-radius:var(--r);cursor:pointer;transition:background var(--tr);-webkit-tap-highlight-color:transparent}
.s-item:hover,.s-item:active{background:var(--bg3)}
.s-item.act{background:var(--ac-bg);border:1px solid rgba(124,106,247,.15)}
.s-item.act .s-it{color:var(--ac2)}
.s-item.jc .s-it::before{content:"⚡ ";font-size:10px}
.s-it{font-size:13px;color:var(--tx2);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:1;line-height:1.4}
.s-del{width:24px;height:24px;border-radius:5px;display:none;place-items:center;color:var(--tx3);flex-shrink:0;transition:all var(--tr)}
.s-item:hover .s-del{display:grid}
.s-del:hover{background:var(--rd-bg);color:var(--rd)}
.s-del svg{width:12px;height:12px;stroke:currentColor;stroke-width:2;fill:none}

.s-foot{padding:8px 8px 12px;border-top:1px solid var(--br);flex-shrink:0}
.s-user{display:flex;align-items:center;gap:9px;padding:8px 10px;border-radius:var(--r);margin-bottom:2px}
.av{width:32px;height:32px;border-radius:50%;background:linear-gradient(135deg,var(--ac),var(--ac2));display:grid;place-items:center;font-size:11px;font-weight:700;color:white;flex-shrink:0;letter-spacing:.5px}
.u-n{font-size:13px;font-weight:500;color:var(--tx);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.u-e{font-size:11px;color:var(--tx3);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-top:1px}
.s-lnk{display:flex;align-items:center;gap:8px;padding:8px 10px;border-radius:var(--r);font-size:13px;color:var(--tx3);width:100%;transition:all var(--tr);-webkit-tap-highlight-color:transparent}
.s-lnk:hover{background:var(--bg3);color:var(--tx2)}
.s-lnk svg{width:15px;height:15px;stroke:currentColor;stroke-width:1.8;fill:none;flex-shrink:0}

.topbar{height:52px;border-bottom:1px solid var(--br);display:flex;align-items:center;justify-content:space-between;padding:0 12px;background:var(--bg2);flex-shrink:0;gap:6px}
.tb-l{display:flex;align-items:center;gap:6px;min-width:0;flex:1}
.tb-t{font-size:13.5px;font-weight:500;color:var(--tx2);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:200px}
.tb-r{display:flex;align-items:center;gap:2px;flex-shrink:0}
.badge{display:inline-flex;align-items:center;gap:4px;padding:3px 9px;border-radius:20px;font-size:11px;font-weight:600;white-space:nowrap;flex-shrink:0}
.badge.rag{background:var(--bl-bg);color:var(--bl);border:1px solid rgba(96,165,250,.15)}
.badge.job{background:var(--am-bg);color:var(--am);cursor:pointer;border:1px solid rgba(251,191,36,.15)}
.badge.job:hover{filter:brightness(1.1)}
@media(max-width:480px){.badge{display:none}}

.job-banner{background:rgba(251,191,36,.04);border-bottom:1px solid rgba(251,191,36,.12);padding:8px 14px;display:flex;align-items:flex-start;gap:8px;font-size:12.5px;color:var(--am);flex-shrink:0;flex-wrap:wrap}
.job-banner>svg{margin-top:1px;flex-shrink:0;width:14px;height:14px;stroke:currentColor;stroke-width:2;fill:none}
.jb-acts{display:flex;align-items:center;gap:6px;margin-left:auto;flex-shrink:0}
.jb-btn{font-size:11px;font-weight:600;padding:3px 10px;border-radius:6px;transition:all var(--tr);color:var(--am);-webkit-tap-highlight-color:transparent}
.jb-btn:hover{background:var(--am-bg)}
.jb-btn.muted{color:var(--tx3)}.jb-btn.muted:hover{background:var(--bg4);color:var(--tx2)}

.chat-area{flex:1;overflow-y:auto;padding:20px 0 8px;-webkit-overflow-scrolling:touch}
.ci{max-width:720px;margin:0 auto;padding:0 16px;display:flex;flex-direction:column;gap:16px}
@media(min-width:600px){.ci{padding:0 24px;gap:20px}}

.empty{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px;text-align:center;padding:40px 20px}
.empty-ico{width:52px;height:52px;border-radius:16px;background:var(--bg3);border:1px solid var(--br);display:grid;place-items:center;margin-bottom:8px}
.empty-ico svg{width:24px;height:24px;stroke:var(--tx3);stroke-width:1.5;fill:none}
.empty h2{font-size:18px;font-weight:600;color:var(--tx);letter-spacing:-.3px;margin-bottom:4px}
@media(min-width:480px){.empty h2{font-size:20px}}
.empty p{font-size:13.5px;color:var(--tx3);max-width:300px;line-height:1.7}
.chips{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;margin-top:12px}
.chip{padding:7px 13px;border:1px solid var(--br2);border-radius:20px;font-size:12px;color:var(--tx3);cursor:pointer;transition:all var(--tr);background:transparent;-webkit-tap-highlight-color:transparent}
.chip:hover,.chip:active{border-color:var(--ac);color:var(--ac);background:var(--ac-bg)}

.msg{display:flex;gap:8px;align-items:flex-start}
@media(min-width:480px){.msg{gap:10px}}
.msg.user{flex-direction:row-reverse}
.mav{width:28px;height:28px;border-radius:8px;display:grid;place-items:center;font-size:10px;font-weight:700;flex-shrink:0;letter-spacing:.3px}
.mav.ai{background:var(--ac);color:white}
.mav.user{background:var(--bg4);color:var(--tx2);border:1px solid var(--br2)}
.mbub{max-width:86%;display:flex;flex-direction:column;gap:3px}
@media(min-width:600px){.mbub{max-width:80%}}
.mc{padding:10px 13px;border-radius:14px;font-size:14px;line-height:1.72;word-break:break-word;overflow-wrap:anywhere}
@media(min-width:480px){.mc{padding:11px 15px}}
.msg.ai .mc{background:var(--bg3);border:1px solid var(--br);border-bottom-left-radius:4px;color:var(--tx)}
.msg.user .mc{background:var(--ac);color:white;border-bottom-right-radius:4px}
.msg.user .mc *{color:white!important}
.mm{font-size:10.5px;color:var(--tx3);padding:2px 4px}
.msg.user .mm{text-align:right}

.md{display:flex;text-align:left;flex-direction:column;gap:6px}
.md-p{line-height:1.75;color:inherit;margin:0}
.md-p+.md-p{margin-top:2px}
.md-h1{font-size:18px;font-weight:700;color:var(--tx);letter-spacing:-.3px;padding-bottom:6px;border-bottom:1px solid var(--br);margin:6px 0 2px}
.md-h2{font-size:15px;font-weight:700;color:var(--tx);letter-spacing:-.2px;margin:8px 0 2px}
.md-h3{font-size:14px;font-weight:600;color:var(--tx2);margin:6px 0 2px}
.msg.user .md-h1,.msg.user .md-h2,.msg.user .md-h3{color:white;border-color:rgba(255,255,255,.25)}
.md-ul,.md-ol{padding-left:20px;display:flex;flex-direction:column;gap:3px;margin:2px 0}
.md-ul li,.md-ol li{line-height:1.65;color:inherit;padding-left:2px}
.md-ul{list-style:disc}.md-ol{list-style:decimal}

.md-code-wrap{background:var(--bg);border:1px solid var(--br2);border-radius:10px;overflow:hidden;margin:4px 0}
.msg.user .md-code-wrap{background:rgba(0,0,0,.25);border-color:rgba(255,255,255,.15)}
.md-code-lang{padding:6px 12px 5px;font-size:10.5px;font-family:var(--mono);font-weight:600;color:var(--tx3);text-transform:uppercase;letter-spacing:.06em;border-bottom:1px solid var(--br2);background:var(--bg2)}
.msg.user .md-code-lang{background:rgba(0,0,0,.2);color:rgba(255,255,255,.5);border-color:rgba(255,255,255,.1)}
.md-code-wrap pre{padding:12px 14px;overflow-x:auto;font-size:13px;font-family:var(--mono);line-height:1.6;background:transparent}
.md-code-wrap pre code{color:var(--tx);font-size:13px;font-family:var(--mono);background:none;border:none;padding:0}
.msg.user .md-code-wrap pre code{color:white}
.mc code:not(.md-code-wrap code){background:var(--bg4);border:1px solid var(--br2);border-radius:4px;padding:1px 5px;font-family:var(--mono);font-size:12.5px;color:var(--ac2)}
.msg.user .mc code:not(.md-code-wrap code){background:rgba(255,255,255,.15);border-color:rgba(255,255,255,.2);color:white}

.md-table-wrap{overflow-x:auto;border-radius:8px;border:1px solid var(--br2);margin:4px 0;-webkit-overflow-scrolling:touch}
.md-table{width:100%;border-collapse:collapse;font-size:13px}
.md-table th{background:var(--bg4);color:var(--tx2);font-weight:600;font-size:12px;padding:8px 12px;text-align:left;white-space:nowrap;border-bottom:1px solid var(--br2)}
.md-table td{padding:7px 12px;border-bottom:1px solid var(--br);color:var(--tx);vertical-align:top;line-height:1.55}
.md-table tr:last-child td{border-bottom:none}
.md-table tr:hover td{background:var(--bg3)}

.md-bq{border-left:3px solid var(--ac);padding:8px 12px;background:var(--ac-bg);border-radius:0 8px 8px 0;margin:4px 0}
.md-bq p{color:var(--tx2);font-size:13.5px;line-height:1.6;font-style:italic}
.msg.user .md-bq{border-color:rgba(255,255,255,.5);background:rgba(255,255,255,.1)}
.msg.user .md-bq p{color:rgba(255,255,255,.85)}
.md-hr{border:none;border-top:1px solid var(--br2);margin:4px 0}

/* RAG source tag */
.rtag{display:inline-flex;align-items:center;gap:4px;margin-top:8px;padding:3px 8px;background:var(--bl-bg);border:1px solid rgba(96,165,250,.15);border-radius:6px;font-size:10.5px;color:var(--bl);font-weight:500}

/* RAG debug indicator — shows in dev */
.rag-debug{font-size:10px;color:var(--tx3);padding:2px 6px;background:var(--bg4);border-radius:4px;margin-top:4px;font-family:var(--mono)}

.typing{display:flex;gap:5px;align-items:center;padding:12px 16px;background:var(--bg3);border:1px solid var(--br);border-radius:14px 14px 14px 4px;width:fit-content}
.td{width:5px;height:5px;border-radius:50%;background:var(--tx3);animation:tda 1.4s infinite ease-in-out}
.td:nth-child(2){animation-delay:.22s}.td:nth-child(3){animation-delay:.44s}
@keyframes tda{0%,80%,100%{opacity:.2;transform:scale(.7)}40%{opacity:1;transform:scale(1)}}

.iw{padding:8px 12px 16px;flex-shrink:0;}
@media(min-width:600px){.iw{padding:10px 20px 20px}}
@supports(padding-bottom:env(safe-area-inset-bottom)){.iw{padding-bottom:calc(16px + env(safe-area-inset-bottom))}}
.ib2{max-width:720px;margin:0 auto}
.ifield{display:flex;align-items:flex-end;gap:6px;background:var(--bg3);border:1.5px solid var(--br2);border-radius:var(--rl);padding:7px;transition:border-color var(--tr),box-shadow var(--tr)}
.ifield:focus-within{border-color:var(--ac);box-shadow:0 0 0 3px var(--ac-bg)}
.ifield textarea{flex:1;background:none;border:none;outline:none;font-size:15px;color:var(--tx);resize:none;max-height:140px;min-height:34px;line-height:1.6;padding:3px 4px;-webkit-appearance:none}
@media(min-width:480px){.ifield textarea{font-size:14px;padding:3px 6px}}
.ifield textarea::placeholder{color:var(--tx3)}
.send{width:36px;height:36px;border-radius:9px;background:var(--ac);display:grid;place-items:center;transition:all var(--tr);flex-shrink:0;-webkit-tap-highlight-color:transparent}
@media(min-width:480px){.send{width:34px;height:34px}}
.send:hover:not(:disabled){background:var(--ac2);transform:scale(1.04)}
.send:active:not(:disabled){transform:scale(.96)}
.send:disabled{background:var(--bg4);cursor:not-allowed;opacity:.5}
.send svg{width:15px;height:15px;stroke:white;stroke-width:2.2;fill:none}
.pw{position:relative;flex-shrink:0}
.pb{width:36px;height:36px;border-radius:9px;display:grid;place-items:center;color:var(--tx3);transition:all var(--tr);position:relative;-webkit-tap-highlight-color:transparent}
@media(min-width:480px){.pb{width:34px;height:34px}}
.pb:hover{background:var(--bg4);color:var(--tx2)}
.pb.active{color:var(--ac);background:var(--ac-bg)}
.pb svg{width:19px;height:19px;stroke:currentColor;stroke-width:1.8;fill:none}
.ddot{position:absolute;top:2px;right:2px;width:15px;height:15px;background:var(--bl);border-radius:50%;font-size:8px;color:white;font-weight:700;display:grid;place-items:center;border:2px solid var(--bg3)}
.pmenu{position:absolute;bottom:calc(100% + 8px);left:0;background:var(--bg2);border:1px solid var(--br2);border-radius:var(--rl);padding:5px;min-width:220px;box-shadow:var(--shl);z-index:200;animation:pop .14s ease}
@keyframes pop{from{opacity:0;transform:scale(.95) translateY(4px)}to{opacity:1;transform:scale(1) translateY(0)}}
.pmi{display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:8px;font-size:13.5px;color:var(--tx);width:100%;transition:background var(--tr);-webkit-tap-highlight-color:transparent}
.pmi:hover,.pmi:active{background:var(--bg3)}
.pmi .pmi-label{flex:1;text-align:left;font-size:13px}
.pmi .pmi-badge{font-size:10px;color:var(--tx3);background:var(--bg4);padding:2px 7px;border-radius:5px}
.pmi svg{width:16px;height:16px;stroke:currentColor;stroke-width:1.8;fill:none;flex-shrink:0}
.pmi.doc svg{color:var(--bl)}.pmi.job svg{color:var(--am)}.pmi.dis{color:var(--rd)}.pmi.dis svg{color:var(--rd)}
.pmsep{height:1px;background:var(--br);margin:4px 0}
.ihint{font-size:11px;color:var(--tx3);margin-top:6px;text-align:center;display:none}
@media(min-width:480px){.ihint{display:block}}

.auth-w{height:100dvh;display:grid;place-items:center;background:var(--bg);padding:16px;overflow-y:auto}
.auth-c{background:var(--bg2);border:1px solid var(--br);border-radius:var(--rxl);padding:28px 24px;width:100%;max-width:400px;box-shadow:var(--shl)}
@media(min-width:480px){.auth-c{padding:36px 32px}}
.auth-logo{display:flex;align-items:center;gap:10px;justify-content:center;margin-bottom:24px}
.auth-m{width:36px;height:36px;background:var(--ac);border-radius:10px;display:grid;place-items:center;flex-shrink:0}
.auth-m svg{width:19px;height:19px;fill:white}
.auth-mn{font-size:20px;font-weight:700;letter-spacing:-.5px}
.ah{font-size:20px;font-weight:700;letter-spacing:-.4px;margin-bottom:5px}
@media(min-width:480px){.ah{font-size:22px}}
.as{font-size:13.5px;color:var(--tx3);margin-bottom:22px;line-height:1.55}
.fg{margin-bottom:13px}
.fl{font-size:11px;font-weight:700;color:var(--tx3);margin-bottom:5px;display:block;letter-spacing:.04em;text-transform:uppercase}
.fi{width:100%;padding:10px 12px;background:var(--bg3);border:1.5px solid var(--br2);border-radius:9px;font-size:15px;color:var(--tx);outline:none;transition:border-color var(--tr),box-shadow var(--tr);-webkit-appearance:none}
@media(min-width:480px){.fi{font-size:14px}}
.fi:focus{border-color:var(--ac);box-shadow:0 0 0 3px var(--ac-bg)}
.fi::placeholder{color:var(--tx3)}
.fb{width:100%;padding:12px;border-radius:10px;font-size:15px;font-weight:600;background:var(--ac);color:white;transition:all var(--tr);margin-top:6px;-webkit-tap-highlight-color:transparent}
@media(min-width:480px){.fb{font-size:14px;padding:11px}}
.fb:hover:not(:disabled){background:var(--ac2);box-shadow:0 4px 16px rgba(124,106,247,.3)}
.fb:active:not(:disabled){transform:scale(.98)}
.fb:disabled{opacity:.55;cursor:not-allowed}
.asw{text-align:center;margin-top:16px;font-size:13px;color:var(--tx3)}
.asw button{color:var(--ac);font-size:13px;font-weight:600}
.ferr{font-size:12.5px;color:var(--rd);margin-top:6px;background:var(--rd-bg);border:1px solid rgba(248,113,113,.15);padding:8px 11px;border-radius:8px;line-height:1.4}

.mover{position:fixed;inset:0;background:rgba(0,0,0,.75);display:flex;align-items:flex-end;justify-content:center;z-index:1000;overflow-y:auto;backdrop-filter:blur(6px)}
@media(min-width:600px){.mover{align-items:flex-start;padding:20px 16px}}
.jp{background:var(--bg2);border:1px solid var(--br2);border-radius:var(--rxl) var(--rxl) 0 0;width:100%;max-width:760px;box-shadow:var(--shl);animation:mdin .22s ease;overflow:hidden;max-height:95dvh;display:flex;flex-direction:column}
@media(min-width:600px){.jp{border-radius:var(--rxl);margin:auto;max-height:90dvh;animation:mdins .2s ease}}
@keyframes mdin{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}
@keyframes mdins{from{opacity:0;transform:translateY(-8px) scale(.98)}to{opacity:1;transform:translateY(0) scale(1)}}
.jp-h{padding:16px 18px 12px;border-bottom:1px solid var(--br);background:linear-gradient(135deg,rgba(251,191,36,.04),transparent);display:flex;align-items:flex-start;justify-content:space-between;gap:12px;flex-shrink:0}
@media(min-width:480px){.jp-h{padding:20px 24px 16px}}
.jp-hl{flex:1;min-width:0}
.jp-ti{font-size:17px;font-weight:700;letter-spacing:-.3px;display:flex;align-items:center;gap:9px;color:var(--tx)}
@media(min-width:480px){.jp-ti{font-size:18px}}
.jp-ticon{width:30px;height:30px;background:var(--am-bg);border:1px solid rgba(251,191,36,.2);border-radius:8px;display:grid;place-items:center;flex-shrink:0}
.jp-ticon svg{width:14px;height:14px;stroke:var(--am);stroke-width:2;fill:none}
.jp-sub{font-size:12px;color:var(--tx3);margin-top:4px;line-height:1.5;padding-left:39px}
.jp-steps{display:flex;align-items:center;margin-top:12px;flex-wrap:wrap;gap:1px;overflow-x:auto;-webkit-overflow-scrolling:touch;padding-bottom:2px}
.jp-s{display:flex;align-items:center;gap:4px;font-size:11px;font-weight:500;color:var(--tx3);cursor:pointer;padding:4px 7px;border-radius:7px;transition:all var(--tr);white-space:nowrap;flex-shrink:0;-webkit-tap-highlight-color:transparent}
.jp-s:hover{color:var(--tx2);background:var(--bg3)}
.jp-s.act{color:var(--am);background:var(--am-bg)}
.jp-s.done{color:var(--gn)}
.jp-sn{width:20px;height:19px;border-radius:50%;background:var(--bg4);display:grid;place-items:center;font-size:9px;font-weight:700;flex-shrink:0}
.jp-s.act .jp-sn{background:var(--am);color:#1a1000}
.jp-s.done .jp-sn{background:var(--gn);color:#001a0a}
.jp-sep{width:12px;height:1px;background:var(--br2);flex-shrink:0}
.jp-xbtn{width:28px;height:28px;border-radius:7px;display:grid;place-items:center;color:var(--tx3);transition:all var(--tr);flex-shrink:0;-webkit-tap-highlight-color:transparent}
.jp-xbtn:hover{background:var(--bg4);color:var(--tx)}
.jp-xbtn svg{width:15px;height:15px;stroke:currentColor;stroke-width:2;fill:none}
.jp-body{padding:16px 18px 20px;display:flex;flex-direction:column;gap:14px;overflow-y:auto;flex:1;-webkit-overflow-scrolling:touch}
@media(min-width:480px){.jp-body{padding:18px 24px 22px;gap:16px}}
.jp-sec-h{font-size:10px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--tx3);padding-bottom:8px;border-bottom:1px solid var(--br);display:flex;align-items:center;gap:5px;margin-bottom:2px}
.jp-sec-h svg{width:11px;height:11px;stroke:currentColor;stroke-width:2;fill:none}
.g2{display:grid;grid-template-columns:1fr;gap:10px}
@media(min-width:480px){.g2{grid-template-columns:1fr 1fr}}
.gf{grid-column:1/-1}
.jf{display:flex;flex-direction:column;gap:4px}
.jl{font-size:10.5px;font-weight:700;color:var(--tx3);text-transform:uppercase;letter-spacing:.04em}
.ji{padding:9px 11px;background:var(--bg3);border:1.5px solid var(--br2);border-radius:8px;font-size:14px;color:var(--tx);outline:none;width:100%;transition:border-color var(--tr),box-shadow var(--tr);-webkit-appearance:none}
@media(min-width:480px){.ji{font-size:13.5px;padding:8px 11px}}
.ji:focus{border-color:var(--ac);box-shadow:0 0 0 3px var(--ac-bg)}
.ji::placeholder{color:var(--tx3)}
.jsel{padding:9px 11px;background:var(--bg3);border:1.5px solid var(--br2);border-radius:8px;font-size:14px;color:var(--tx);outline:none;width:100%;transition:border-color var(--tr);appearance:none;cursor:pointer;-webkit-appearance:none}
@media(min-width:480px){.jsel{font-size:13.5px;padding:8px 11px}}
.jsel:focus{border-color:var(--ac)}
.jta{padding:9px 11px;background:var(--bg3);border:1.5px solid var(--br2);border-radius:8px;font-size:14px;color:var(--tx);outline:none;width:100%;resize:vertical;min-height:72px;line-height:1.6;transition:border-color var(--tr);-webkit-appearance:none}
@media(min-width:480px){.jta{font-size:13px;padding:8px 11px}}
.jta:focus{border-color:var(--ac)}
.jta::placeholder{color:var(--tx3)}
.jhi{font-size:11px;color:var(--tx3);margin-top:2px}
.proj-list{display:flex;flex-direction:column;gap:8px}
.proj{background:var(--bg3);border:1px solid var(--br);border-radius:10px;padding:12px;display:flex;flex-direction:column;gap:8px;position:relative}
.proj-x{position:absolute;top:10px;right:10px;width:22px;height:22px;border-radius:6px;display:grid;place-items:center;color:var(--tx3);transition:all var(--tr)}
.proj-x:hover{background:var(--rd-bg);color:var(--rd)}
.proj-x svg{width:11px;height:11px;stroke:currentColor;stroke-width:2;fill:none}
.add-p{display:flex;align-items:center;gap:7px;padding:10px 12px;border-radius:9px;border:1.5px dashed var(--br2);font-size:13px;color:var(--tx3);transition:all var(--tr);width:100%;justify-content:center;-webkit-tap-highlight-color:transparent}
.add-p:hover,.add-p:active{border-color:var(--ac);color:var(--ac);background:var(--ac-bg)}
.add-p svg{width:14px;height:14px;stroke:currentColor;stroke-width:2;fill:none}
.cpg{display:grid;grid-template-columns:1fr;gap:7px}
@media(min-width:480px){.cpg{grid-template-columns:1fr 1fr}}
.cpi{display:flex;align-items:center;gap:8px;background:var(--bg3);border:1px solid var(--br);border-radius:8px;padding:8px 11px;transition:border-color var(--tr)}
.cpi:focus-within{border-color:var(--ac)}
.cpl{font-size:10px;font-weight:700;color:var(--tx3);min-width:72px;text-transform:uppercase;letter-spacing:.03em;flex-shrink:0}
.cpinp{background:none;border:none;outline:none;font-size:13.5px;color:var(--tx);flex:1;min-width:0;-webkit-appearance:none}
.cpinp::placeholder{color:var(--tx3)}
.rdrop{border:1.5px dashed var(--br2);border-radius:10px;padding:20px 16px;text-align:center;cursor:pointer;transition:all var(--tr);font-size:13px;color:var(--tx3);line-height:1.6;-webkit-tap-highlight-color:transparent}
.rdrop:hover,.rdrop:active{border-color:var(--am);color:var(--am);background:var(--am-bg)}
.rdrop svg{width:22px;height:22px;stroke:currentColor;stroke-width:1.5;fill:none;margin:0 auto 8px;display:block;opacity:.6}
.rdrop.has{border-color:var(--gn);color:var(--gn);background:var(--gn-bg)}
.rdrop.has svg{opacity:1}
.jp-foot{padding:12px 18px;border-top:1px solid var(--br);display:flex;align-items:center;justify-content:flex-end;gap:8px;background:var(--bg2);flex-shrink:0}
@media(min-width:480px){.jp-foot{padding:14px 24px}}
.jp-cancel{padding:9px 16px;border-radius:8px;font-size:13.5px;font-weight:500;color:var(--tx2);border:1px solid var(--br2);transition:all var(--tr);-webkit-tap-highlight-color:transparent}
.jp-cancel:hover{background:var(--bg4);color:var(--tx)}
.jp-ok{padding:9px 20px;border-radius:8px;font-size:13.5px;font-weight:700;background:var(--am);color:#1a1000;transition:all var(--tr);-webkit-tap-highlight-color:transparent}
.jp-ok:hover{filter:brightness(1.07);box-shadow:0 4px 14px rgba(251,191,36,.3)}
.jp-ok:active{transform:scale(.97)}

.dp{width:100%;height:auto;max-height:60dvh;background:var(--bg2);border-top:1px solid var(--br);display:flex;flex-direction:column;position:fixed;bottom:0;left:0;right:0;z-index:50;animation:dpsli .2s ease;border-radius:var(--rxl) var(--rxl) 0 0;box-shadow:var(--shl)}
@media(min-width:600px){.dp{position:relative;width:256px;min-width:256px;height:100%;max-height:none;border-top:none;border-left:1px solid var(--br);border-radius:0;bottom:auto;animation:sli .2s ease}}
@keyframes dpsli{from{transform:translateY(100%)}to{transform:translateY(0)}}
@keyframes sli{from{transform:translateX(100%)}to{transform:translateX(0)}}
.dp-h{padding:12px 14px;border-bottom:1px solid var(--br);display:flex;align-items:center;justify-content:space-between;flex-shrink:0}
.dp-t{font-size:13px;font-weight:600;color:var(--tx)}
.dp-list{flex:1;overflow-y:auto;padding:6px;-webkit-overflow-scrolling:touch}
.dp-item{display:flex;align-items:center;gap:8px;padding:8px 9px;border-radius:var(--r);transition:background var(--tr)}
.dp-item:hover{background:var(--bg3)}
.dp-ico{width:28px;height:28px;border-radius:7px;background:var(--bl-bg);border:1px solid rgba(96,165,250,.12);display:grid;place-items:center;flex-shrink:0}
.dp-ico svg{width:13px;height:13px;stroke:var(--bl);stroke-width:1.8;fill:none}
.dp-n{font-size:12px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--tx)}
.dp-c{font-size:10.5px;color:var(--tx3);margin-top:1px}
.dp-x{width:22px;height:22px;border-radius:5px;display:none;place-items:center;color:var(--tx3);transition:all var(--tr);flex-shrink:0}
.dp-item:hover .dp-x{display:grid}
.dp-x:hover{background:var(--rd-bg);color:var(--rd)}
.dp-x svg{width:12px;height:12px;stroke:currentColor;stroke-width:2;fill:none}
.dp-up{margin:8px;border:1.5px dashed var(--br2);border-radius:var(--r);padding:16px;text-align:center;cursor:pointer;font-size:12px;color:var(--tx3);transition:all var(--tr);line-height:1.6;-webkit-tap-highlight-color:transparent}
.dp-up:hover,.dp-up:active{border-color:var(--ac);color:var(--ac);background:var(--ac-bg)}
.dp-up svg{width:20px;height:20px;stroke:currentColor;stroke-width:1.5;fill:none;margin:0 auto 6px;display:block;opacity:.5}
.dp-up:hover svg{opacity:1}

.set{height:100%;overflow-y:auto;padding:24px 16px;-webkit-overflow-scrolling:touch}
@media(min-width:600px){.set{padding:36px 32px}}
.set-in{max-width:540px;margin:0 auto}
.set-h{font-size:20px;font-weight:700;letter-spacing:-.4px;margin-bottom:4px;color:var(--tx)}
@media(min-width:480px){.set-h{font-size:22px}}
.set-s{font-size:13.5px;color:var(--tx3);margin-bottom:24px;line-height:1.5}
.set-sec{margin-bottom:20px}
.set-sh{font-size:10px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:var(--tx3);margin-bottom:8px}
.set-card{background:var(--bg2);border:1px solid var(--br);border-radius:var(--rl);overflow:hidden}
.set-row{display:flex;align-items:center;justify-content:space-between;padding:13px 14px;transition:background var(--tr);gap:12px}
@media(min-width:480px){.set-row{padding:13px 16px}}
.set-row+.set-row{border-top:1px solid var(--br)}
.set-row:hover{background:var(--bg3)}
.set-rl{font-size:13.5px;font-weight:500;color:var(--tx)}
.set-rd{font-size:12px;color:var(--tx3);margin-top:2px}
.tgl{width:38px;height:22px;border-radius:11px;background:var(--bg5);position:relative;transition:background var(--tr);cursor:pointer;flex-shrink:0;-webkit-tap-highlight-color:transparent}
.tgl.on{background:var(--ac)}
.tgl::after{content:'';position:absolute;width:16px;height:16px;border-radius:50%;background:white;top:3px;left:3px;transition:transform var(--tr);box-shadow:0 1px 3px rgba(0,0,0,.3)}
.tgl.on::after{transform:translateX(16px)}
.tag{padding:3px 9px;border-radius:20px;font-size:11px;font-weight:600}
.tag.g{background:var(--gn-bg);color:var(--gn);border:1px solid rgba(52,211,153,.15)}

.toast{position:fixed;bottom:22px;right:16px;left:16px;background:var(--bg2);border:1px solid var(--br2);border-radius:11px;padding:11px 14px;font-size:13px;box-shadow:var(--shl);z-index:9999;animation:tin .2s ease;line-height:1.4;text-align:center}
@media(min-width:480px){.toast{left:auto;right:22px;max-width:320px;text-align:left}}
.toast.s{border-color:rgba(52,211,153,.4);color:var(--gn);background:var(--gn-bg)}
.toast.e{border-color:rgba(248,113,113,.4);color:var(--rd);background:var(--rd-bg)}
@keyframes tin{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
.spin{animation:sp .75s linear infinite}@keyframes sp{to{transform:rotate(360deg)}}
@media(min-width:600px){.dp-backdrop{display:none!important}}

/* ── Job Cards ── */
.msg-outer{display:flex;flex-direction:column;gap:10px}
.jc-wrap{display:flex;flex-direction:column;gap:10px;margin-top:12px;width:100%}
.jc-header{display:flex;align-items:center;justify-content:space-between;padding:0 2px;margin-bottom:4px}
.jc-count{font-size:11px;font-weight:700;color:var(--tx3);text-transform:uppercase;letter-spacing:.07em}
.jc-refetch{display:flex;align-items:center;gap:5px;font-size:12px;font-weight:600;color:var(--ac);padding:4px 10px;border-radius:7px;transition:all var(--tr);border:1px solid var(--ac-bg);-webkit-tap-highlight-color:transparent}
.jc-refetch:hover{background:var(--ac-bg)}
.jc-refetch svg{width:12px;height:12px;stroke:currentColor;stroke-width:2;fill:none}
.jcard{background:var(--bg2);border:1px solid var(--br2);border-radius:var(--rl);overflow:hidden;transition:border-color var(--tr),box-shadow var(--tr)}
.jcard:hover{border-color:var(--ac);box-shadow:0 4px 20px rgba(124,106,247,.08)}
.jcard-top{padding:14px 16px 10px;display:flex;align-items:flex-start;gap:12px}
.jcard-logo{width:40px;height:40px;border-radius:10px;background:var(--bg3);border:1px solid var(--br);display:grid;place-items:center;font-size:14px;font-weight:700;color:var(--tx2);flex-shrink:0;letter-spacing:-.5px;text-transform:uppercase;font-family:var(--mono)}
.jcard-info{flex:1;min-width:0}
.jcard-title{font-size:14px;font-weight:600;color:var(--tx);letter-spacing:-.2px;line-height:1.3;margin-bottom:2px}
.jcard-company{font-size:13px;color:var(--tx2);font-weight:500}
.jcard-loc{font-size:11.5px;color:var(--tx3);margin-top:2px}
.jcard-score-wrap{flex-shrink:0;display:flex;flex-direction:column;align-items:flex-end;gap:4px}
.jcard-score-num{font-size:20px;font-weight:700;letter-spacing:-.5px;line-height:1}
.jcard-score-num.high{color:var(--gn)}.jcard-score-num.mid{color:var(--am)}.jcard-score-num.low{color:var(--bl)}
.jcard-score-label{font-size:9px;font-weight:700;color:var(--tx3);text-transform:uppercase;letter-spacing:.06em}
.jcard-score-bar{width:48px;height:3px;background:var(--bg4);border-radius:2px;overflow:hidden}
.jcard-score-fill{height:100%;border-radius:2px;transition:width .6s ease}
.jcard-score-fill.high{background:linear-gradient(90deg,var(--gn),#22c55e)}
.jcard-score-fill.mid{background:linear-gradient(90deg,var(--am),#f59e0b)}
.jcard-score-fill.low{background:linear-gradient(90deg,var(--bl),#3b82f6)}
.jcard-pills{padding:0 16px 10px;display:flex;flex-wrap:wrap;gap:5px}
.jcard-pill{padding:3px 8px;border-radius:20px;font-size:11px;font-weight:500;white-space:nowrap}
.jcard-pill.salary{background:var(--gn-bg);color:var(--gn);border:1px solid rgba(52,211,153,.15)}
.jcard-pill.exp{background:var(--bl-bg);color:var(--bl);border:1px solid rgba(96,165,250,.15)}
.jcard-pill.type{background:var(--bg4);color:var(--tx2);border:1px solid var(--br)}
.jcard-pill.portal{background:var(--ac-bg);color:var(--ac2);border:1px solid rgba(124,106,247,.15)}
.jcard-skills{padding:0 16px 12px;display:flex;flex-wrap:wrap;gap:4px}
.jcard-skill{padding:2px 7px;border-radius:5px;font-size:11px;font-weight:500;background:var(--bg3);color:var(--tx3);border:1px solid var(--br);font-family:var(--mono)}
.jcard-divider{height:1px;background:var(--br);margin:0 16px}
.jcard-why{padding:8px 16px;font-size:11.5px;color:var(--tx3);display:flex;align-items:center;gap:6px;line-height:1.4}
.jcard-why svg{width:11px;height:11px;stroke:var(--gn);stroke-width:2;fill:none;flex-shrink:0}
/* Crack it section */
.jcard-crack{border-top:1px solid var(--br)}
.jcard-crack-toggle{display:flex;align-items:center;gap:7px;font-size:12px;font-weight:600;color:var(--ac);padding:10px 16px;width:100%;transition:background var(--tr);-webkit-tap-highlight-color:transparent}
.jcard-crack-toggle:hover{background:var(--ac-bg)}
.jcard-crack-toggle svg{width:13px;height:13px;stroke:currentColor;stroke-width:2;fill:none;transition:transform var(--tr)}
.jcard-crack-toggle.open .chev{transform:rotate(180deg)}
.jcard-crack-body{padding:0 16px 14px;display:flex;flex-direction:column;gap:8px;font-size:12.5px;color:var(--tx2);line-height:1.65;border-top:1px solid var(--br)}
.jcard-crack-tip{display:flex;flex-direction:column;gap:2px}
.jcard-crack-tip strong{color:var(--tx);font-weight:600;font-size:12px}
/* Actions */
.jcard-actions{padding:10px 16px 14px;display:flex;gap:8px;align-items:center}
.jcard-apply{flex:1;padding:9px 16px;border-radius:9px;background:var(--ac);color:white;font-size:13px;font-weight:600;text-align:center;transition:all var(--tr);display:flex;align-items:center;justify-content:center;gap:6px;text-decoration:none;-webkit-tap-highlight-color:transparent}
.jcard-apply:hover{background:var(--ac2);transform:translateY(-1px);box-shadow:0 4px 14px rgba(124,106,247,.3)}
.jcard-apply:active{transform:translateY(0)}
.jcard-apply.disabled{background:var(--bg4);color:var(--tx3);cursor:default;box-shadow:none;transform:none}
.jcard-apply svg{width:13px;height:13px;stroke:white;stroke-width:2;fill:none}
.jcard-bm{width:36px;height:36px;border-radius:9px;border:1px solid var(--br2);display:grid;place-items:center;color:var(--tx3);transition:all var(--tr);flex-shrink:0;-webkit-tap-highlight-color:transparent}
.jcard-bm:hover{border-color:var(--am);color:var(--am);background:var(--am-bg)}
.jcard-bm svg{width:14px;height:14px;stroke:currentColor;stroke-width:1.8;fill:none}


/* ── Add these lines inside your existing CSS string in Chat.jsx ── */
 
/* Whiteboard button — slightly muted vs New Conversation */
.s-wb {
  margin-top: 6px;
  background: transparent;
  color: var(--tx2);
  border: 1px solid var(--br);
}
.s-wb:hover {
  background: var(--hover);
  color: var(--tx1);
  border-color: var(--ac);
}
.s-wb svg {
  flex-shrink: 0;
}

.main-wrap {
  display: flex;
  flex: 1;
  overflow: hidden;
  min-width: 0;
}
 
/* .main stays exactly as-is, just becomes flexible */
.main {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}
 
/* ── Drag handle between chat and board ── */
.board-drag-handle {
  width: 5px;
  background: var(--br, #2e2e36);
  cursor: col-resize;
  flex-shrink: 0;
  transition: background 0.15s;
  position: relative;
}
.board-drag-handle:hover { background: var(--ac, #6c63ff); }
.board-drag-handle::after {
  content: '⋮';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #4a4a5a;
  font-size: 14px;
  pointer-events: none;
}
 
/* ── Board panel ── */
.board-panel {
  display: flex;
  flex-direction: column;
  height: 100%;
  background: #0f0f10;
  flex-shrink: 0;
  overflow: hidden;
}
 
/* Board topbar */
.board-panel-topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 52px;
  padding: 0 14px;
  background: var(--bg2);
  border-bottom: 1px solid var(--br);
  flex-shrink: 0;
}
 
.board-panel-title {
  display: flex;
  align-items: center;
  gap: 7px;
  font-size: 13px;
  font-weight: 600;
  color: var(--tx1, #e8e8f0);
}
 
.board-close-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 26px;
  height: 26px;
  border: none;
  border-radius: 6px;
  background: transparent;
  color: var(--tx3, #a0a0b0);
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}
.board-close-btn:hover { background: var(--hv, #25252d); color: var(--tx1, #e8e8f0); }
 
/* Canvas fills rest of panel */
.board-canvas {
  flex: 1;
  overflow: hidden;
  position: relative;
}
.board-canvas .tl-container {
  height: 100% !important;
}
 
/* Active state for sidebar whiteboard button */
.s-wb.active {
  background: var(--ac-dim, #6c63ff22);
  color: var(--ac, #6c63ff);
  border-color: var(--ac, #6c63ff);
}
 
/* Make the app flex row so sidebar + main-wrap sit side by side */
.app {
  display: flex !important;
  flex-direction: row !important;
  height: 100vh;
  overflow: hidden;
}
`;

