// ═══════════════════ JOB CARD COMPONENTS ════════════════════════
// CrackIt: expandable interview tips per job
function CrackIt({ job }) {
  const [open, setOpen] = useState(false);
  const tips = [
    job.skills?.length > 0 && {
      label: "Key skills to highlight",
      text: job.skills.join(", "),
    },
    job.matchWhy && {
      label: "Why you match",
      text: job.matchWhy,
    },
    {
      label: "Interview prep",
      text: "Research " + job.company + "'s products and recent news. Prepare STAR stories around your " +
            (job.skills?.[0] || "core") + " experience. Expect system design if senior-level.",
    },
    {
      label: "Resume tip",
      text: "Tailor your headline to " + job.title + " — mirror their exact title. Quantify impact in bullets.",
    },
    job.salary !== "Not disclosed" && {
      label: "Salary negotiation",
      text: "Posted range: " + job.salary + ". Come prepared with Levels.fyi / Glassdoor data to anchor higher.",
    },
  ].filter(Boolean);

  return (
    <div className="jcard-crack">
      <button
        className={"jcard-crack-toggle" + (open ? " open" : "")}
        onClick={() => setOpen(o => !o)}
      >
        <svg viewBox="0 0 24 24"><path d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"/></svg>
        How to crack this interview
        <svg viewBox="0 0 24 24" className="chev" style={{marginLeft:"auto"}}><polyline points="6 9 12 15 18 9"/></svg>
      </button>
      {open && (
        <div className="jcard-crack-body">
          {tips.map((tip, i) => (
            <div key={i} className="jcard-crack-tip">
              <strong>{tip.label}:</strong>
              <span>{tip.text}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// Single job card
function JobCard({ job }) {
  const score = job.matchScore || 0;
  const tier = score >= 50 ? "high" : score >= 25 ? "mid" : "low";
  const logo = (job.company || "??").slice(0, 2).toUpperCase();

  return (
    <div className="jcard">
      <div className="jcard-top">
        <div className="jcard-logo">{logo}</div>
        <div className="jcard-info">
          <div className="jcard-title">{job.title}</div>
          <div className="jcard-company">{job.company}</div>
          {job.location && <div className="jcard-loc">{job.location}</div>}
        </div>
        <div className="jcard-score-wrap">
          <div className={"jcard-score-num " + tier}>
            {score}<span style={{fontSize:11,fontWeight:400,color:"var(--tx3)"}}>%</span>
          </div>
          <div className="jcard-score-label">match</div>
          <div className="jcard-score-bar">
            <div className={"jcard-score-fill " + tier} style={{width: Math.min(score,100) + "%"}}/>
          </div>
        </div>
      </div>

      <div className="jcard-pills">
        <span className="jcard-pill salary">{job.salary}</span>
        <span className="jcard-pill exp">{job.experience}</span>
        {job.jobType  && <span className="jcard-pill type">{job.jobType}</span>}
        {job.portal   && <span className="jcard-pill portal">{job.portal}</span>}
      </div>

      {job.skills?.length > 0 && (
        <div className="jcard-skills">
          {job.skills.map((s, i) => <span key={i} className="jcard-skill">{s}</span>)}
        </div>
      )}

      {job.matchWhy && (
        <>
          <div className="jcard-divider"/>
          <div className="jcard-why">
            <svg viewBox="0 0 24 24"><polyline points="20 6 9 17 4 12"/></svg>
            {job.matchWhy}
          </div>
        </>
      )}

      <CrackIt job={job}/>

      <div className="jcard-actions">
        {job.applyUrl ? (
          <a className="jcard-apply" href={job.applyUrl} target="_blank" rel="noreferrer">
            Apply Now
            <svg viewBox="0 0 24 24"><path d="M18 13v6a2 2 0 01-2 2H5a2 2 0 01-2-2V8a2 2 0 012-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg>
          </a>
        ) : (
          <span className="jcard-apply disabled">No link available</span>
        )}
        <button className="jcard-bm" title="Bookmark">
          <svg viewBox="0 0 24 24"><path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/></svg>
        </button>
      </div>
    </div>
  );
}

// Job cards list — renders below AI message bubble
function JobCards({ jobs, onRefetch }) {
  if (!jobs?.length) return null;
  return (
    <div className="jc-wrap">
      <div className="jc-header">
        <span className="jc-count">{jobs.length} job{jobs.length !== 1 ? "s" : ""} matched</span>
        <button className="jc-refetch" onClick={onRefetch}>
          <svg viewBox="0 0 24 24"><polyline points="23 4 23 10 17 10"/><polyline points="1 20 1 14 7 14"/><path d="M3.51 9a9 9 0 0114.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0020.49 15"/></svg>
          Refresh
        </button>
      </div>
      {jobs.map((job, i) => <JobCard key={job.id || i} job={job}/>)}
    </div>
  );
}

// ═══════════════════ TOAST ═══════════════════════════════════════
function Toast({ msg, type, onDone }) {
  useEffect(()=>{const t=setTimeout(onDone,2800);return()=>clearTimeout(t);},[]);
  return <div className={`toast ${type}`}>{msg}</div>;
}

// ═══════════════════ MAIN APP ════════════════════════════════════
// Persist snapshot to localStorage so it survives refresh
const saveSnapshot = (snapshot) => {
  try { localStorage.setItem("nx_board_snapshot", JSON.stringify(snapshot)); } catch {}
};
const loadSnapshot = () => {
  try { const s = localStorage.getItem("nx_board_snapshot"); return s ? JSON.parse(s) : null; } catch { return null; }
};

export default function App() {
  const [user,setUser]=useState(()=>S.get("nx_session"));
  const [theme,setTheme]=useState(()=>S.get("nx_theme")||"dark");
  const [chats,setChats]=useState(()=>S.get("nx_chats")||{});
  const [cid,setCid]=useState(null);
  const [page,setPage]=useState("chat");
  const [plusMenu,setPlusMenu]=useState(false);
  const [showDocs,setShowDocs]=useState(false);
  const [showJobModal,setShowJobModal]=useState(false);
  const [loading,setLoading]=useState(false);
  const [input,setInput]=useState("");
  const [toast,setToast]=useState(null);
  const [sidebar,setSidebar]=useState(()=>window.innerWidth>768);
  const endRef=useRef();
  const inputRef=useRef();
  const rag=useRef(new RAGStore());

  // ADD these lines right after your last useState (after the rag=useRef line)
 
// ─── Whiteboard state (declare ONCE) ─────────────────────────────────────────
const [boardOpen, setBoardOpen] = useState(false);
const [boardWidth, setBoardWidth] = useState(520);


 
// Resizable divider handler
const startBoardDrag = (e) => {
  e.preventDefault();
  const onMove = (e) => {
    const newBoardW = window.innerWidth - e.clientX;
    setBoardWidth(Math.min(Math.max(newBoardW, 300), window.innerWidth * 0.65));
  };
  const onUp = () => {
    window.removeEventListener("mousemove", onMove);
    window.removeEventListener("mouseup", onUp);
  };
  window.addEventListener("mousemove", onMove);
  window.addEventListener("mouseup", onUp);
};
 
// tldraw mount handler
// const handleBoardMount = (editor) => {
//   const saved = loadSnapshot();
//   if (saved) { try { editor.loadSnapshot(saved); } catch (e) {} }
//   const unsub = editor.store.listen(
//     () => saveSnapshot(editor.getSnapshot()),
//     { scope: "document" }
//   );
//   return () => unsub();
// };

const handleBoardMount = useCallback((editor) => {
  const saved = loadSnapshot();
  if (saved) { try { editor.loadSnapshot(saved); } catch (e) {} }
  const unsub = editor.store.listen(
    () => saveSnapshot(editor.getSnapshot()),
    { scope: "document" }
  );
  return () => unsub();
}, []); 

  useEffect(()=>{document.documentElement.setAttribute("data-theme",theme);S.set("nx_theme",theme);},[theme]);

  // Load pdf.js from CDN
  useEffect(()=>{
    if(window.pdfjsLib)return;
    const s=document.createElement("script");
    s.src="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
    s.onload=()=>{
      if(window.pdfjsLib){
        window.pdfjsLib.GlobalWorkerOptions.workerSrc=
          "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
      }
    };
    document.head.appendChild(s);
  },[]);

  useEffect(()=>{endRef.current?.scrollIntoView({behavior:"smooth"});},[chats,cid,loading]);

  // ── FIX 1: Re-index when chat switches OR when docs change for current chat ──
  // Depends on both cid AND the docs array of the active chat
  // Uses ragTextStore (module-level Map) — not localStorage — for raw text
  const activeChatDocs = cid ? (chats[cid]?.docs || []) : [];
  const docsKey = activeChatDocs.map(d=>d.id).join(",");

  useEffect(()=>{
    const store = rag.current;
    store.clear(); // reset via encapsulated method
    let indexed = 0, missing = 0;
    for (const doc of activeChatDocs) {
      const rawText = RTS.get(doc.id);
      if (rawText) {
        store.add(doc.id, doc.name, rawText);
        indexed++;
      } else {
        missing++;
        console.warn(`[RAG] rawText missing for "${doc.name}" (id: ${doc.id}) — was the page refreshed in a new tab?`);
      }
    }
    if (indexed > 0) {
      console.log(`[RAG] Indexed ${indexed} doc(s), ${store.size} total chunks for chat ${cid}`);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cid, docsKey]);

  const toast2=(msg,type="default")=>setToast({msg,type,id:uid()});
  const save=upd=>{setChats(upd);S.set("nx_chats",upd);};

  const activeChat=cid?chats[cid]:null;
  const msgs=activeChat?.messages||[];
  const jobOn=!!activeChat?.jobMode;
  const jobProfile=activeChat?.jobProfile||null;
  const docs=activeChat?.docs||[];

  const newChat=()=>{
    const id=uid();
    const upd={[id]:{id,title:"New Chat",messages:[],createdAt:now(),updatedAt:now(),jobMode:false,jobProfile:null,docs:[]},...chats};
    save(upd);setCid(id);setInput("");setPage("chat");
    if(window.innerWidth<=768)setSidebar(false);
  };

  const delChat=id=>{
    // Clean up sessionStorage entries for deleted chat's docs
    const chatDocs = chats[id]?.docs || [];
    chatDocs.forEach(d => RTS.del(d.id));
    const upd={...chats};delete upd[id];save(upd);
    if(cid===id)setCid(Object.keys(upd)[0]||null);
  };

  // ── normalizeProfileForMatch ─────────────────────────────────────────────────
  // Converts the raw 6-step form jobProfile into what /match expects.
  // The form stores techStack/frameworks/etc as comma strings and separate fields.
  // The server expects a flat object with merged skills array + numeric experience.
  const normalizeProfileForMatch = (profile) => {
    // Merge all skill-related fields into one array
    const allSkillsRaw = [
      profile.techStack    || "",
      profile.frameworks   || "",
      profile.databases    || "",
      profile.cloud        || "",
    ].join(",");

    const skills = allSkillsRaw
      .split(/[,\s]+/)
      .map(s => s.trim().toLowerCase())
      .filter(s => s.length > 1);

    // Parse experience: "fresher"/"0" → 0, "2 years" → 2, "3" → 3
    const expRaw = (profile.experience || "").toLowerCase();
    let experience = 0;
    if (/fresher|trainee|student|intern|0/.test(expRaw)) {
      experience = 0;
    } else {
      const match = expRaw.match(/(\d+)/);
      experience = match ? parseInt(match[1], 10) : 0;
    }

    // Normalise location_type from jobType field
    const jobTypeLower = (profile.jobType || "").toLowerCase();
    const locationType =
      jobTypeLower.includes("remote")  ? "remote"  :
      jobTypeLower.includes("hybrid")  ? "hybrid"  :
      jobTypeLower.includes("onsite")  ? "onsite"  : null;

    return {
      targetRole:   profile.targetRole   || "",
      location:     profile.preferredLocations || profile.location || "",
      experience,
      skills,
      jobType:      profile.jobType      || "",
      ...(locationType ? { location_type: locationType } : {}),
    };
  };

  // ── fetchAndShowJobs ────────────────────────────────────────────────────────
  // Core orchestrator: fetch jobs → AI intro → save message with jobCards
  // Accepts the current chats snapshot to avoid stale closure issues
  const fetchAndShowJobs = async (profile, chatId, chatsSnapshot) => {
    const cur = chatsSnapshot || chats;
    setLoading(true);

    // Add user trigger message so conversation reads naturally
    const trigMsg = { id: uid(), role: "user", content: "Find matching jobs for me", timestamp: now() };
    const withTrig = {
      ...cur,
      [chatId]: {
        ...cur[chatId],
        messages: [...(cur[chatId].messages || []), trigMsg],
        updatedAt: now(),
      },
    };
    save(withTrig);

    try {
      // ── 1. Fetch from backend ──────────────────────────────────────────────
      let jobCards = [];
      let fetchError = null;
      try {
        const matchProfile = normalizeProfileForMatch(profile);
        console.log("[Jobs] Sending to /match:", JSON.stringify(matchProfile));
        const raw = await getJobsForUser(matchProfile);
        console.log("[Jobs] Received:", raw?.length, "jobs");
        jobCards = (raw || []).map(formatJob);
      } catch (e) {
        fetchError = e.message;
        console.error("[Jobs] Fetch failed:", e);
      }

      // ── 2. Build AI system prompt with job context ─────────────────────────
      const jobSys = buildJobSystem(profile);
      let aiSys = jobSys;

      if (jobCards.length > 0) {
        // Give AI a preview of top 6 jobs to write a contextual intro
        const preview = jobCards.slice(0, 6).map((j, i) =>
          (i + 1) + ". " + j.title + " @ " + j.company +
          " | " + j.salary + " | " + j.experience +
          " | " + j.location +
          " | Match: " + j.matchScore + "%" +
          (j.matchWhy ? " (" + j.matchWhy + ")" : "")
        ).join("\n");

        aiSys += "\n\nLIVE JOB RESULTS (" + jobCards.length + " jobs fetched now):\n" + preview +
          "\n\nWrite a warm 2-3 sentence intro about these results." +
          " Highlight the best match and total count." +
          " End with: \'Here are your top matches:\'" +
          " — do NOT list the jobs yourself, the UI renders rich cards.";
      } else if (fetchError) {
        aiSys += "\n\nThe job service returned an error: " + fetchError +
          ". Apologise briefly and suggest the user try again or refine their profile.";
      } else {
        aiSys += "\n\nNo jobs were found matching this profile." +
          " Suggest how the user can broaden their search or improve their profile.";
      }

      // ── 3. Call AI for intro text ──────────────────────────────────────────
      const history = (withTrig[chatId].messages || []).slice(-6)
        .map(m => ({ role: m.role, content: m.content }));
    //   const intro = await callAI(history, aiSys, groqKey);
        const intro = await callAI(history, aiSys);

      // ── 4. Save AI message with jobCards attached ──────────────────────────
      const aiMsg = {
        id:        uid(),
        role:      "assistant",
        content:   intro,
        timestamp: now(),
        jobCards:  jobCards.length > 0 ? jobCards : null,
        jobError:  fetchError || null,
      };
      const fin = { ...withTrig };
      fin[chatId] = {
        ...fin[chatId],
        messages: [...fin[chatId].messages, aiMsg],
        updatedAt: now(),
      };
      save(fin);
    } catch (e) {
      toast2(e.message || "Error fetching jobs.", "e");
    } finally {
      setLoading(false);
    }
  };

  // ── activateJob: save profile → auto-fetch ──────────────────────────────────
  const activateJob = async (profile) => {
    if (!cid) return;
    const updatedChats = {
      ...chats,
      [cid]: { ...chats[cid], jobMode: true, jobProfile: profile, updatedAt: now() },
    };
    save(updatedChats);
    setShowJobModal(false);
    toast2("⚡ Job Search Mode activated! Fetching matches…", "s");
    // Auto-fetch immediately on activation
    await fetchAndShowJobs(profile, cid, updatedChats);
  };

  const disableJob=()=>{
    if(!cid)return;
    save({...chats,[cid]:{...chats[cid],jobMode:false,updatedAt:now()}});
    toast2("Job Search Mode disabled.","default");
  };

  const handleSend=async()=>{
    const text=input.trim();
    if(!text||loading)return;
    let chatId=cid;
    let cur={...chats};
    if(!chatId){
      chatId=uid();
      cur[chatId]={id:chatId,title:text.slice(0,40),messages:[],createdAt:now(),updatedAt:now(),jobMode:false,jobProfile:null,docs:[]};
      setCid(chatId);
    }
    const um={id:uid(),role:"user",content:text,timestamp:now()};
    cur[chatId]={...cur[chatId],messages:[...(cur[chatId].messages||[]),um],
      title:cur[chatId].messages.length===0?text.slice(0,40):cur[chatId].title,updatedAt:now()};
    save({...cur});setInput("");setLoading(true);
    try{
      // ── Job intent: intercept before normal AI call ──────────────────────────
      if (cur[chatId].jobMode && cur[chatId].jobProfile && isJobIntent(text)) {
        setLoading(false); // fetchAndShowJobs manages its own loading state
        await fetchAndShowJobs(cur[chatId].jobProfile, chatId, cur);
        return;
      }

      let sys=`You are Nexus, an intelligent AI assistant. Be helpful, insightful, and clear.

FORMAT RULES (always follow):
- Use **bold** for key terms, important points, and labels
- Use ## headings to separate major sections when the answer has multiple parts
- Use bullet lists (- item) for collections of items, steps, or options
- Use numbered lists for sequential steps or ranked items
- Use \`inline code\` for code terms, commands, file names
- Use fenced code blocks with language tag (\`\`\`python) for code samples
- Use > blockquote for important callouts or warnings
- Use tables for comparisons (| Col | Col |)
- Keep paragraphs short — 2-4 sentences max
- For short/simple answers, skip structure and just answer naturally`;

      if(cur[chatId].jobMode&&cur[chatId].jobProfile) sys=buildJobSystem(cur[chatId].jobProfile);

      // ── RAG: structured retrieval + context injection ────────────────────────
            if (rag.current.docCount > 0) {
        const ragHits = rag.current.query(text, 8);
        if (ragHits.length > 0) {
          const intent = classifyIntent(text);
          const isFullDoc = ragHits[0]?.isFullDoc;
          const docNames = [...new Set(ragHits.map(r => r.name || r.docName))].filter(Boolean).join(", ");

          let ctx = "";
          if (isFullDoc) {
            ctx = ragHits.map(r =>
              "=== " + r.name + " ===\n" + r.text + "\n=== END " + r.name + " ==="
            ).join("\n\n");
          } else {
            const bySec = {};
            for (const hit of ragHits) {
              const sec = hit.metadata?.section || "general";
              if (!bySec[sec]) bySec[sec] = [];
              bySec[sec].push(hit);
            }
            ctx = Object.entries(bySec).map(([sec, hits]) => {
              const secLabel = sec.charAt(0).toUpperCase() + sec.slice(1).replace(/_/g, " ");
              const body = hits.map(h => {
                const entityLabel = h.metadata?.entity
                  ? "[" + h.metadata.entity + (h.metadata.dates ? " | " + h.metadata.dates : "") + "]\n"
                  : "";
                return entityLabel + h.text;
              }).join("\n\n");
              return "## " + secLabel + "\n" + body;
            }).join("\n\n---\n\n");
          }

          const divider = "=".repeat(60);
          sys += "\n\n" + divider + "\n"
            + "DOCUMENT: " + docNames + "\n"
            + divider + "\n"
            + ctx + "\n"
            + divider + "\n"
            + "END OF DOCUMENT\n"
            + divider + "\n\n"
            + "INSTRUCTIONS:\n"
            + "1. Answer ONLY using the document content above\n"
            + "2. Copy names, titles, companies, dates EXACTLY as written\n"
            + "3. If asked about a specific company or project, use ONLY that entity's data\n"
            + "4. Do NOT mix information from different companies or projects\n"
            + "5. If the answer is not in the document, say so explicitly\n"
            + "6. Include specific numbers, dates, and achievements from the document";

          console.log("[RAG] hits=" + ragHits.length + " sections=" + [...new Set(ragHits.map(r => r.metadata?.section))].join(","));
        }
      }

      const history = (cur[chatId].messages||[]).slice(-14).map(m=>({role:m.role,content:m.content}));
    //   const reply = await callAI(history,sys,groqKey);
      const reply = await callAI(history, sys);
      

      const ragSource = rag.current.docCount > 0 ? (rag.current.docs[0]?.name || null) : null;
      const am = {id:uid(),role:"assistant",content:reply,timestamp:now(),ragSource};
      const fin = {...cur}; fin[chatId] = {...fin[chatId],messages:[...fin[chatId].messages,am],updatedAt:now()};
      save(fin);
    } catch(e) { toast2(e.message||"API error.","e"); }
    setLoading(false);
  };

  // ── PDF extraction — preserves line structure using y-coordinate grouping ────
  const extractPdfText = async (file) => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
          const typedArray = new Uint8Array(e.target.result);
          const lib = window.pdfjsLib;
          if (!lib) { reject(new Error("PDF.js not loaded yet — try again in a moment.")); return; }
          const pdf = await lib.getDocument({ data: typedArray }).promise;
          const pages = [];

          for (let p = 1; p <= pdf.numPages; p++) {
            const page = await pdf.getPage(p);
            const content = await page.getTextContent();

            // Group text items by their y-coordinate (vertical position)
            // Items on the same line have the same y; different y = new line
            const lineMap = new Map();
            for (const item of content.items) {
              if (!item.str || !item.str.trim()) continue;
              // y is transform[5], round to nearest 2px to group near items
              const y = Math.round(item.transform[5] / 2) * 2;
              if (!lineMap.has(y)) lineMap.set(y, []);
              lineMap.get(y).push({ x: item.transform[4], str: item.str });
            }

            // Sort lines top-to-bottom (descending y in PDF coords)
            const sortedYs = [...lineMap.keys()].sort((a, b) => b - a);
            const lines = sortedYs.map(y => {
              // Sort items left-to-right within each line
              const items = lineMap.get(y).sort((a, b) => a.x - b.x);
              return items.map(i => i.str).join(" ").trim();
            }).filter(Boolean);

            pages.push(lines.join("\n"));
          }

          resolve(pages.join("\n\n").trim());
        } catch(err) { reject(err); }
      };
      reader.onerror = reject;
      reader.readAsArrayBuffer(file);
    });
  };

  // ── FIX 3: Upload stores raw text in ragTextStore, NOT localStorage ────────
  const handleUpload = async (file) => {
    if (!cid) { toast2("Open or create a chat first.", "e"); return; }
    const ext = "." + file.name.split(".").pop().toLowerCase();
    const textTypes = [".txt",".md",".js",".ts",".jsx",".tsx",".py",".json",".csv",".html",".css",".xml",".yaml",".yml",".env",".sh",".sql",".java",".cpp",".c",".rs",".go",".rb",".php"];
    const isPdf = ext === ".pdf";
    if (!isPdf && !textTypes.includes(ext)) {
      toast2(`Unsupported: ${ext}. Use PDF, TXT, MD, or code files.`, "e"); return;
    }
    if (file.size > 20 * 1024 * 1024) { toast2("File too large (max 20MB).", "e"); return; }

    toast2(`Processing "${file.name}"…`, "default");

    let rawText = "";
    if (isPdf) {
      try { rawText = await extractPdfText(file); }
      catch (err) { toast2(`PDF error: ${err.message}`, "e"); return; }
    } else {
      rawText = await file.text().catch(() => "");
    }

    if (!rawText || rawText.trim().length < 10) {
      toast2("File appears empty or unreadable.", "e"); return;
    }

    // Check for duplicate doc name in this chat
    const existingDocs = chats[cid]?.docs || [];
    const existing = existingDocs.find(d => d.name === file.name);
    const docId = existing ? existing.id : uid();

    // ── Store raw text in sessionStorage (survives refresh, ~10MB/key) ──
    const stored = RTS.set(docId, rawText);
    if (!stored) { toast2("Storage full — try a smaller file.", "e"); return; }

    // ── Index immediately in current RAGStore ──
    const chunkCount = rag.current.add(docId, file.name, rawText);
    console.log(`[RAG] Indexed "${file.name}": ${chunkCount} chunks, ${rawText.length} chars`);

    // ── Save only metadata to chat/localStorage (no rawText = stays lean) ──
    const newDoc = {
      id: docId,
      name: file.name,
      chunks: chunkCount,
      size: file.size,
      isPdf,
      addedAt: now(),
    };
    const prevDocs = existingDocs.filter(d => d.id !== docId);
    const updatedChats = {
      ...chats,
      [cid]: { ...chats[cid], docs: [...prevDocs, newDoc], updatedAt: now() }
    };
    save(updatedChats);
    toast2(`"${file.name}" — ${chunkCount} chunks indexed!`, "s");
  };

  // ── FIX 4: Delete cleans up ragTextStore too ───────────────────────────────
  const handleDocDel = id => {
    if(!cid)return;
    RTS.del(id);                      // remove from sessionStorage
    rag.current.remove(id);           // remove from index
    const updDocs=(chats[cid]?.docs||[]).filter(d=>d.id!==id);
    save({...chats,[cid]:{...chats[cid],docs:updDocs,updatedAt:now()}});
    toast2("Document removed.","default");
  };

  const chatList=Object.values(chats).sort((a,b)=>new Date(b.updatedAt)-new Date(a.updatedAt));
  const grouped=chatList.reduce((acc,c)=>{const l=fmtDate(c.updatedAt);if(!acc[l])acc[l]=[];acc[l].push(c);return acc;},{});

  if(!user)return<><style>{CSS}</style><Auth onAuth={u=>setUser(u)}/></>;
  const ini=user.name.split(" ").map(w=>w[0]).join("").toUpperCase().slice(0,2);

  return(
    <>
      <style>{CSS}</style>
      <div className={`app ${sidebar?"":"collapsed"}`}>

        {sidebar&&<div className={`sidebar-overlay${sidebar?" visible":""}`} onClick={()=>setSidebar(false)}/>}

        <div className={`sidebar${sidebar?" open":""}`}>
          <div className="s-head">
            <div className="logo"><div className="logo-dot"><I.Logo/></div><span className="logo-name">Nexus</span></div>
            <button className="ib" onClick={()=>setSidebar(false)}><I.X/></button>
          </div>
          <button className="s-new" onClick={newChat}><I.Plus/>New conversation</button>
          {/* ── Add this block right after the "New conversation" button ── */}
            {/* REPLACE your existing Whiteboard button with this */}
            <button
            className={`s-new s-wb ${boardOpen ? "active" : ""}`}
            onClick={() => {
                setBoardOpen(b => !b);
                if (window.innerWidth <= 768) setSidebar(false);
            }}
            >
            <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
                stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <rect x="3" y="3" width="18" height="14" rx="2"/>
                <line x1="8" y1="21" x2="16" y2="21"/>
                <line x1="12" y1="17" x2="12" y2="21"/>
            </svg>
            Whiteboard
            </button>
          <div className="s-hist">
            {Object.entries(grouped).map(([lbl,items])=>(
              <div key={lbl}>
                <div className="s-gl">{lbl}</div>
                {items.map(c=>(
                  <div key={c.id} className={`s-item ${cid===c.id?"act":""} ${c.jobMode?"jc":""}`} onClick={()=>{setCid(c.id);setPage("chat");if(window.innerWidth<=768)setSidebar(false);}}>
                    <div className="s-it">{c.title}</div>
                    <button className="s-del" onClick={e=>{e.stopPropagation();delChat(c.id);}}><I.Trash/></button>
                  </div>
                ))}
              </div>
            ))}
            {!chatList.length&&<div style={{padding:"18px 9px",textAlign:"center",color:"var(--tx3)",fontSize:12}}>No chats yet.</div>}
          </div>
          <div className="s-foot">
            <div className="s-user">
              <div className="av">{ini}</div>
              <div style={{flex:1,minWidth:0}}><div className="u-n">{user.name}</div><div className="u-e">{user.email}</div></div>
            </div>
            <button className="s-lnk" onClick={()=>{setPage("settings");if(window.innerWidth<=768)setSidebar(false);}}><I.Settings/>Settings</button>
            <button className="s-lnk" onClick={()=>{S.del("nx_session");setUser(null);}}><I.Logout/>Sign out</button>
          </div>
        </div>

        <div className="main-wrap">
            <div className="main">
          {page==="settings"?(
            <Sett user={user} theme={theme} onTheme={()=>setTheme(t=>t==="dark"?"light":"dark")} onBack={()=>setPage("chat")}/>
          ):(
            <>
              <div className="topbar">
                <div className="tb-l">
                  <button className="ib" onClick={()=>setSidebar(s=>!s)}><I.Menu/></button>
                  <span className="tb-t">{activeChat?.title||"Nexus AI"}</span>
                  {docs.length>0&&(
                    <span className="badge rag" onClick={()=>setShowDocs(true)} style={{cursor:"pointer"}}>
                      <I.File style={{width:11,height:11}}/>
                      {docs.length} doc{docs.length!==1?"s":""} · {docs.reduce((s,d)=>s+(d.chunks||0),0)} chunks
                    </span>
                  )}
                  {jobOn&&<span className="badge job" onClick={()=>setShowJobModal(true)}>⚡ Job Mode</span>}
                </div>
                <div className="tb-r">
                  <button className="ib" onClick={()=>setTheme(t=>t==="dark"?"light":"dark")}>
                    {theme==="dark"?<I.Sun/>:<I.Moon/>}
                  </button>
                </div>
              </div>

              {jobOn&&jobProfile&&(
                <div className="job-banner">
                  <I.Briefcase/>
                  <span>
                    <strong>Job Search Mode</strong> — {jobProfile.name||user.name}
                    {jobProfile.targetRole?` · ${jobProfile.targetRole}`:""}
                    {jobProfile.experience?` · ${jobProfile.experience}`:""}
                    {jobProfile.techStack?` · ${jobProfile.techStack.split(",")[0].trim()}…`:""}
                  </span>
                  <div className="jb-acts">
                    <button className="jb-btn muted" onClick={()=>setShowJobModal(true)}>
                      <I.Edit style={{width:11,height:11,display:"inline",verticalAlign:"middle",marginRight:3}}/>Edit
                    </button>
                    <button className="jb-btn" onClick={disableJob}>Disable</button>
                  </div>
                </div>
              )}

              <div className="chat-area">
                {!msgs.length?(
                  <div className="ci" style={{height:"100%",justifyContent:"center"}}>
                    <div className="empty">
                      <div className="empty-ico">{jobOn?<I.Briefcase/>:<I.Chat/>}</div>
                      <h2>{jobOn?`Hi ${(jobProfile?.name||user.name).split(" ")[0]}! Let's land that job.`:"Ask me anything"}</h2>
                      <p>{jobOn
                        ?`I know your profile — ${jobProfile?.targetRole||"your role"}, ${jobProfile?.experience||""} experience, ${jobProfile?.techStack?.split(",")[0]?.trim()||"your stack"}. Ask me anything about your job search.`
                        :"I remember our conversations, read your documents, and help you find jobs."}</p>
                      <div className="chips">
                        {(jobOn
                          ?["Find matching jobs for me","Review my resume","Mock interview — SDE-2","Negotiate my salary","Best companies for my stack","Write a cold email to a recruiter"]
                          :["Summarize a document","Help with my resume","Explain this code","Career tips"]
                        ).map(s=>(
                          <button key={s} className="chip" onClick={()=>{setInput(s);inputRef.current?.focus();}}>{s}</button>
                        ))}
                      </div>
                    </div>
                  </div>
                ):(
                  <div className="ci">
                    {msgs.map(m=>(
                      <div key={m.id} className="msg-outer">
                        <div className={`msg ${m.role}`}>
                          <div className={`mav ${m.role}`}>{m.role==="user"?ini:"N"}</div>
                          <div className="mbub">
                            <div className="mc">
                              <Markdown text={m.content}/>
                              {m.ragSource&&(
                                <div className="rtag">
                                  <svg viewBox="0 0 24 24" style={{width:10,height:10,stroke:"currentColor",strokeWidth:2,fill:"none",flexShrink:0}}>
                                    <path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/>
                                  </svg>
                                  {m.ragSource}
                                </div>
                              )}
                            </div>
                            <div className="mm">{fmtTime(m.timestamp)}</div>
                          </div>
                        </div>
                        {m.jobCards && m.jobCards.length > 0 && (
                          <div className="jc-outer">
                            <JobCards
                              jobs={m.jobCards}
                              onRefetch={()=>{
                                if(activeChat?.jobProfile && cid){
                                  fetchAndShowJobs(activeChat.jobProfile, cid, chats);
                                }
                              }}
                            />
                          </div>
                        )}
                      </div>
                    ))}
                    {loading&&(
                      <div className="msg ai">
                        <div className="mav ai">N</div>
                        <div className="typing"><div className="td"/><div className="td"/><div className="td"/></div>
                      </div>
                    )}
                    <div ref={endRef}/>
                  </div>
                )}
              </div>

              <div className="iw"><div className="ib2">
                <div className="ifield">
                  <div className="pw">
                    <button className="pb" onClick={()=>setPlusMenu(m=>!m)}>
                      <I.Plus/>
                      {docs.length>0&&<span className="ddot">{docs.length}</span>}
                    </button>
                    {plusMenu&&(
                      <div className="pmenu">
                        <button className="pmi doc" onClick={()=>{setShowDocs(true);setPlusMenu(false);}}>
                          <I.File/><span className="pmi-label">Attach Documents</span><span className="pmi-badge">RAG</span>
                        </button>
                        <div className="pmsep"/>
                        <button className="pmi job" onClick={()=>{
                          setPlusMenu(false);
                          if(!cid){newChat();setTimeout(()=>setShowJobModal(true),60);return;}
                          setShowJobModal(true);
                        }}>
                          <I.Briefcase/>
                          <span className="pmi-label">{jobOn?"Edit Job Profile":"Job Search Mode"}</span>
                          {jobOn&&<span className="pmi-badge" style={{color:"var(--am)",background:"var(--am-bg)"}}>ON</span>}
                        </button>
                        {jobOn&&(
                          <button className="pmi dis" onClick={()=>{disableJob();setPlusMenu(false);}}>
                            <I.X style={{stroke:"var(--rd)"}}/>Disable Job Mode
                          </button>
                        )}
                      </div>
                    )}
                  </div>
                  <textarea ref={inputRef} rows={1}
                    placeholder={jobOn?`Ask about jobs, interviews, ${jobProfile?.targetRole||"your role"}…`:docs.length>0?"Ask about your documents…":"Message Nexus…"}
                    value={input}
                    onChange={e=>{setInput(e.target.value);e.target.style.height="auto";e.target.style.height=Math.min(e.target.scrollHeight,160)+"px";}}
                    onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();handleSend();}}}
                  />
                  <button className="send" onClick={handleSend} disabled={!input.trim()||loading}>
                    {loading
                      ?<svg viewBox="0 0 24 24" width="15" height="15" stroke="white" strokeWidth="2" fill="none" className="spin"><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4"/></svg>
                      :<I.Send/>}
                  </button>
                </div>
                <div className="ihint">Nexus is AI and can make mistakes. Please double-check responses.</div>
              </div></div>
            </>
          )}
        </div> {/* closes .main */}
        {boardOpen && (
            <>
            <div className="board-drag-handle" onMouseDown={startBoardDrag} />
            <div className="board-panel" style={{ width: boardWidth }}>
                <div className="board-panel-topbar">
                <span className="board-panel-title">
                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none"
                    stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <rect x="3" y="3" width="18" height="14" rx="2"/>
                    <line x1="8" y1="21" x2="16" y2="21"/>
                    <line x1="12" y1="17" x2="12" y2="21"/>
                    </svg>
                    Whiteboard
                </span>
                <button className="board-close-btn" onClick={() => setBoardOpen(false)}>
                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none"
                    stroke="currentColor" strokeWidth="2" strokeLinecap="round">
                    <line x1="18" y1="6" x2="6" y2="18"/>
                    <line x1="6" y1="6" x2="18" y2="18"/>
                    </svg>
                </button>
                </div>
                <div className="board-canvas">
                <Tldraw onMount={handleBoardMount} />
                </div>
            </div>
            </>
        )}
        </div> {/* closes .main-wrap */}
      </div> {/* closes .app */}
		{showDocs&&(
          <>
            <div style={{position:"fixed",inset:0,zIndex:49,background:"rgba(0,0,0,.4)"}} className="dp-backdrop" onClick={()=>setShowDocs(false)}/>
            <Docs docs={docs} onUpload={handleUpload} onDelete={handleDocDel} onClose={()=>setShowDocs(false)}/>
          </>
        )}
        {toast&&<Toast key={toast.id} msg={toast.msg} type={toast.type} onDone={()=>setToast(null)}/>}
        {plusMenu&&<div style={{position:"fixed",inset:0,zIndex:99}} onClick={()=>setPlusMenu(false)}/>}
      {showJobModal&&(
        <JobModal initial={jobProfile} onSave={activateJob} onClose={()=>setShowJobModal(false)}/>
      )}
    </>
  );
}